
const MYPDV_VERSION='1.0.3';
const firebaseConfig={apiKey:"AIzaSyAhCd5oWt6JS0aiH2JlH0J-xSnjCuOonHI",authDomain:"my-pdv-85b1e.firebaseapp.com",databaseURL:"https://my-pdv-85b1e-default-rtdb.firebaseio.com",projectId:"my-pdv-85b1e",storageBucket:"my-pdv-85b1e.firebasestorage.app",messagingSenderId:"865647781746",appId:"1:865647781746:web:c6d57b880fac9afe0f1feb"};
let db, auth, cloudOK=false; try{firebase.initializeApp(firebaseConfig);db=firebase.firestore();auth=firebase.auth();cloudOK=true}catch(e){console.warn(e)}
const STORE='maybike_v11_pwa_cloud'; // Mantido para preservar dados locais existentes
const $=id=>document.getElementById(id); const uid=()=>Date.now().toString(36)+Math.random().toString(36).slice(2,7); const today=()=>new Date().toISOString().slice(0,10); const br=d=>d?d.split('-').reverse().join('/'):''; const money=v=>'R$ '+Number(v||0).toLocaleString('pt-BR',{minimumFractionDigits:2}); const n=v=>Number(v||0);
let st={users:[{u:'admin',p:'admin',nome:'Douglas',perfil:'Administrador'}],clientes:[],funcionarios:[],maoObra:[],estoque:[],os:[],vendas:[],caixa:[],contas:[],recorrentes:[],config:{multaPercent:2,jurosMesPercent:1,comissaoMecanicoPercent:5,comissaoVendedorPercent:3,margemPadrao:75,margemMinima:70,garantiaDias:90,revisaoDias:120,metaMensal:30000},seqOS:1,seqVenda:1};
let currentEmpresaId=null, currentUser=null, currentProfile=null, isMaster=false;
function saasLocalKey(){return STORE+'_saas_'+(currentEmpresaId||'sem_empresa')}
function loadLocal(){try{let d=localStorage.getItem(saasLocalKey()); if(d) st={...st,...JSON.parse(d)}}catch(e){}}
function saveLocal(){try{localStorage.setItem(saasLocalKey(),JSON.stringify(st))}catch(e){console.warn(e)}}
function makeEmptyState(){return {users:[],clientes:[],funcionarios:[],maoObra:[],estoque:[],os:[],vendas:[],caixa:[],contas:[],recorrentes:[],bikes:[],bikesVendidas:[],agenda:[],audit:[],config:{multaPercent:2,jurosMesPercent:1,comissaoMecanicoPercent:5,comissaoVendedorPercent:3,margemPadrao:75,margemMinima:70,garantiaDias:90,garantiaPecasDias:90,garantiaMaoObraDias:30,revisaoDias:120,metaMensal:30000},seqOS:1,seqVenda:1,seqDocumento:1,empresa:{nome:'Minha Loja',plano:'Starter',status:'Ativa'}}}
async function loadCloud(){
  if(!currentEmpresaId){st=makeEmptyState();migrateV13(); if($('cloud'))$('cloud').textContent='🔐 Faça login'; return;}
  loadLocal();
  if(cloudOK){try{let doc=await db.collection('empresas').doc(currentEmpresaId).collection('sistema').doc('state').get(); if(doc.exists){st={...makeEmptyState(),...doc.data()};migrateV13();saveLocal()} else {st={...makeEmptyState(),...st};migrateV13();await save()} if($('cloud'))$('cloud').textContent='☁️ My PDV conectado'}catch(e){migrateV13(); if($('cloud'))$('cloud').textContent='⚠️ Erro na nuvem';console.warn(e)}}else {migrateV13(); if($('cloud'))$('cloud').textContent='💾 Local'}}
async function save(){saveLocal(); if(cloudOK&&currentEmpresaId){try{await db.collection('empresas').doc(currentEmpresaId).collection('sistema').doc('state').set(JSON.parse(JSON.stringify(st)),{merge:true}); if($('cloud'))$('cloud').textContent='☁️ My PDV conectado'}catch(e){if($('cloud'))$('cloud').textContent='⚠️ Erro ao salvar';console.warn(e)}} render(current)}
const pages=[['dashboard','📊 Dashboard'],['clientes','👥 Clientes'],['bicicletas','🚲 Bicicletas'],['funcionarios','🧑‍🔧 Funcionários'],['maoobra','🛠️ Mão de Obra'],['estoque','📦 Estoque'],['os','🔧 Ordens de Serviço'],['agenda','📅 Agenda'],['vendas','🛒 Vendas / Recebimento'],['caixa','💰 Caixa'],['contas','🧾 Contas'],['garantias','🛡️ Garantias'],['crm','📱 CRM Revisões'],['relatorios','📈 Relatórios'],['auditoria','🔐 Auditoria'],['config','⚙️ Configurações']]; let current='dashboard';
function nav(){ $('nav').innerHTML=pages.map(p=>`<button id="n-${p[0]}" onclick="go('${p[0]}')">${p[1]}</button>`).join('') } function go(p){current=p;document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));$('p-'+p).classList.add('active');document.querySelectorAll('.nav button').forEach(x=>x.classList.remove('active'));$('n-'+p).classList.add('active');$('title').textContent=pages.find(x=>x[0]==p)[1].replace(/^.. /,'');render(p)}
async function hashPass(p){const enc=new TextEncoder().encode(String(p));const buf=await crypto.subtle.digest('SHA-256',enc);return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('')}
async function doLogin(){let email=$('user').value.trim(),p=$('pass').value; if(!email||!p)return alert('Informe e-mail e senha.'); try{await auth.signInWithEmailAndPassword(email,p)}catch(e){alert('Erro no login: '+(e.message||e))}}
async function logout(){try{await auth.signOut()}catch(e){} sessionStorage.clear();location.reload()}
function statusBadge(s){let c=s=='Faturada'?'b4':s=='Pronta para retirada'?'b3':s=='Aguardando aprovação'?'b2':s=='Cancelada'?'b5':'b1';return `<span class="badge ${c}">${s}</span>`} function calcOS(o){let p=(o.pecas||[]).reduce((a,i)=>a+n(i.qtd)*n(i.preco),0),m=(o.mao||[]).reduce((a,i)=>a+n(i.valor),0),d=n(o.desc);return {pecas:p,mao:m,total:p+m-d}}
function render(p){if(p=='dashboard')dashboard(); if(p=='clientes')clientes(); if(p=='bicicletas')bicicletasPage(); if(p=='funcionarios')funcionarios(); if(p=='maoobra')maoObraPage(); if(p=='estoque')estoque(); if(p=='os')osPage(); if(p=='agenda')agendaPage(); if(p=='vendas')vendas(); if(p=='caixa')caixa(); if(p=='contas')contas(); if(p=='crm')crmPage(); if(p=='relatorios')relatorios(); if(p=='auditoria')auditoriaPage(); if(p=='config')config()}
function migrateV13(){st.config={multaPercent:2,jurosMesPercent:1,comissaoMecanicoPercent:5,comissaoVendedorPercent:3,margemPadrao:75,margemMinima:70,garantiaDias:90,revisaoDias:120,metaMensal:30000,...(st.config||{})};st.recorrentes=st.recorrentes||[];st.contas=(st.contas||[]).map(c=>({...c,valorOriginal:n(c.valorOriginal||c.valor),valor:n(c.valor),status:c.status||'Aberto'}));st.vendas=st.vendas||[];st.caixa=st.caixa||[];st.os=st.os||[];st.maoObra=st.maoObra||[];st.funcionarios=st.funcionarios||[];st.estoque=(st.estoque||[]).map(e=>({...e,precoCompra:n(e.precoCompra||e.custo),ipi:n(e.ipi),frete:n(e.frete),outrosCustos:n(e.outrosCustos),margem:n(e.margem||st.config.margemPadrao),custoReal:n(e.custoReal||e.custo)}));st.clientes=st.clientes||[];st.bikes=st.bikes||[];st.agenda=st.agenda||[];st.audit=st.audit||[];st.categoriasMargem=st.categoriasMargem||[{cat:'Câmaras',margem:70},{cat:'Pneus',margem:70},{cat:'Correntes',margem:75},{cat:'Acessórios',margem:100},{cat:'Bicicletas',margem:20}]}
function addDays(date,days){let d=new Date(date+'T00:00:00');d.setDate(d.getDate()+Number(days||0));return d.toISOString().slice(0,10)}
function monthKey(d){return (d||today()).slice(0,7)}
function daysLate(venc){if(!venc)return 0;let a=new Date(venc+'T00:00:00'),b=new Date(today()+'T00:00:00');return Math.max(0,Math.floor((b-a)/86400000))}
function jurosConta(c){let atraso=daysLate(c.venc);if(atraso<=0||c.status=='Pago')return 0;let multa=n(st.config.multaPercent)/100*n(c.valorOriginal||c.valor);let jurosDia=(n(st.config.jurosMesPercent)/100)/30*n(c.valorOriginal||c.valor)*atraso;return multa+jurosDia}
function totalConta(c){return n(c.valorOriginal||c.valor)+jurosConta(c)}
function statusConta(c){if(c.status=='Pago')return '<span class="badge b3">Pago</span>'; if(daysLate(c.venc)>0)return '<span class="badge b5">Vencida</span>'; let diff=(new Date(c.venc+'T00:00:00')-new Date(today()+'T00:00:00'))/86400000; if(diff<=5)return '<span class="badge b2">A vencer</span>'; return '<span class="badge b1">Aberta</span>'}
function contasAbertas(tipo){return st.contas.filter(c=>c.tipo==tipo&&c.status!='Pago')}
function csvDownload(name,rows){let csv=rows.map(r=>r.map(v=>'"'+String(v??'').replace(/"/g,'""')+'"').join(';')).join('\n');let a=document.createElement('a');a.href=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv;charset=utf-8'}));a.download=name;a.click()}
function wppClean(t){return String(t||'').replace(/\D/g,'')}
function whatsappUrl(msg,fone){return 'https://wa.me/'+(fone?wppClean(fone):'5542988425435')+'?text='+encodeURIComponent(msg)}
function servicoRanking(){let map={};st.os.forEach(o=>(o.mao||[]).forEach(m=>{let k=m.desc||m.nome||'Serviço';map[k]=(map[k]||0)+1}));return Object.entries(map).sort((a,b)=>b[1]-a[1])}
function lucroVenda(v){let custo=(v.itens||[]).reduce((a,i)=>{let prod=st.estoque.find(e=>e.id==i.prodId);return a+n(i.qtd)*(prod?n(prod.custo):0)},0);return n(v.total)-custo}
function comissaoFunc(f){let pct=n(st.config.comissaoMecanicoPercent)/100;let total=st.vendas.filter(v=>v.funcionario==f.nome||v.funcionarioId==f.id).reduce((a,v)=>a+n(v.total)*pct,0);return total}
function gerarRecorrentes(){let now=monthKey(today()), created=0;for(let r of st.recorrentes||[]){if(!r.ativo)continue;let key=r.id+'-'+now;if(st.contas.some(c=>c.recKey==key))continue;let dia=Math.min(28,Number(r.dia||5));st.contas.push({id:uid(),tipo:r.tipo||'A Pagar',venc:now+'-'+String(dia).padStart(2,'0'),valor:n(r.valor),valorOriginal:n(r.valor),desc:r.desc+' (mensal)',status:'Aberto',recorrenteId:r.id,recKey:key});created++}if(created)save()}
function dashboard(){
let hoje=today(),ch=st.caixa.filter(x=>x.data==hoje),entH=ch.filter(x=>x.tipo=='Entrada').reduce((a,b)=>a+n(b.valor),0),saiH=ch.filter(x=>x.tipo=='Saída').reduce((a,b)=>a+n(b.valor),0),ab=st.os.filter(o=>!['Faturada','Cancelada'].includes(o.status)).length,crit=st.estoque.filter(e=>n(e.qtd)<=n(e.min)).length;
let m=monthKey(today()),ano=today().slice(0,4);let vendasMes=st.vendas.filter(v=>monthKey(v.data)==m),vendasAno=st.vendas.filter(v=>(v.data||'').slice(0,4)==ano);
let fatMes=vendasMes.reduce((a,v)=>a+n(v.total),0),fatAno=vendasAno.reduce((a,v)=>a+n(v.total),0);let lucroMes=vendasMes.reduce((a,v)=>a+lucroVenda(v),0);
let recAberto=contasAbertas('A Receber').reduce((a,c)=>a+totalConta(c),0),pagAberto=contasAbertas('A Pagar').reduce((a,c)=>a+totalConta(c),0),resContas=recAberto-pagAberto;
let vencidas=st.contas.filter(c=>c.status!='Pago'&&daysLate(c.venc)>0).length;let aVencer=st.contas.filter(c=>c.status!='Pago'&&daysLate(c.venc)==0&&((new Date(c.venc+'T00:00:00')-new Date(today()+'T00:00:00'))/86400000)<=5).length;
let recent=st.os.slice().reverse().slice(0,6).map(o=>`<tr><td>#${o.num}</td><td>${o.cliente}</td><td>${o.bike}</td><td>${o.funcionario||'—'}</td><td>${money(calcOS(o).total)}</td><td>${statusBadge(o.status)}</td></tr>`).join('');
let rank=servicoRanking().slice(0,5).map(([s,q],i)=>`<tr><td>${i+1}º</td><td>${s}</td><td><b>${q}</b></td></tr>`).join('');
$('p-dashboard').innerHTML=`<div class="grid4"><div class="metric"><div class="label">Faturamento do mês</div><div class="value green">${money(fatMes)}</div></div><div class="metric"><div class="label">Faturamento anual</div><div class="value green">${money(fatAno)}</div></div><div class="metric"><div class="label">Lucro estimado mês</div><div class="value ${lucroMes>=0?'green':'red'}">${money(lucroMes)}</div></div><div class="metric"><div class="label">Contas vencidas</div><div class="value red">${vencidas}</div></div></div><div class="grid4"><div class="metric"><div class="label">Entradas hoje</div><div class="value green">${money(entH)}</div></div><div class="metric"><div class="label">Saídas hoje</div><div class="value red">${money(saiH)}</div></div><div class="metric"><div class="label">OS em aberto</div><div class="value blue">${ab}</div></div><div class="metric"><div class="label">Estoque crítico</div><div class="value gold">${crit}</div></div></div><div class="grid3"><div class="metric"><div class="label">A receber em aberto</div><div class="value green">${money(recAberto)}</div></div><div class="metric"><div class="label">A pagar em aberto</div><div class="value red">${money(pagAberto)}</div></div><div class="metric"><div class="label">Resultado financeiro</div><div class="value ${resContas>=0?'green':'red'}">${resContas>=0?'Lucro':'Prejuízo'} ${money(Math.abs(resContas))}</div><div style="color:var(--mut);margin-top:6px">Contas abertas com juros/multa calculados</div></div></div><div class="grid2"><div class="card"><div class="head"><h3>OS recentes</h3><button class="btn sm" onclick="go('os')">Ver todas</button></div><table class="table"><thead><tr><th>OS</th><th>Cliente</th><th>Bike</th><th>Funcionário</th><th>Total</th><th>Status</th></tr></thead><tbody>${recent||'<tr><td colspan="6" class="empty">Nenhuma OS cadastrada.</td></tr>'}</tbody></table></div><div class="card"><h3>Alertas e ranking</h3><div class="notice">🔔 ${aVencer} conta(s) a vencer em até 5 dias. ${vencidas?`<br>⚠️ ${vencidas} conta(s) vencida(s).`:''}</div><h3>Ranking de serviços</h3><table class="table"><thead><tr><th>#</th><th>Serviço</th><th>Qtd.</th></tr></thead><tbody>${rank||'<tr><td colspan="3" class="empty">Sem serviços executados.</td></tr>'}</tbody></table></div></div>`} 

function clientes(){let rows=st.clientes.map(c=>`<tr><td><b>${c.nome}</b></td><td>${c.cpf||'—'}</td><td>${c.whats||'—'}</td><td>${c.cidade||'—'}</td><td>${c.email||'—'}</td><td><button class="btn sm" onclick="openCliente('${c.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('clientes','${c.id}')">Excluir</button></td></tr>`).join('');$('p-clientes').innerHTML=`<div class="card"><div class="head"><h3>Clientes</h3><button class="btn goldbtn" onclick="openCliente()">+ Novo cliente</button></div><table class="table"><thead><tr><th>Nome</th><th>CPF</th><th>WhatsApp</th><th>Cidade</th><th>E-mail</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="6" class="empty">Nenhum cliente.</td></tr>'}</tbody></table></div>`}
function openCliente(id){let c=st.clientes.find(x=>x.id==id)||{};modal(`<div class="mhead"><h3>${id?'Editar':'Novo'} cliente</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Nome *</label><input id="c_nome" value="${c.nome||''}"></div><div class="field"><label>CPF</label><input id="c_cpf" value="${c.cpf||''}"></div><div class="field"><label>WhatsApp</label><input id="c_whats" value="${c.whats||''}"></div><div class="field"><label>E-mail</label><input id="c_email" value="${c.email||''}"></div><div class="field"><label>CEP</label><input id="c_cep" value="${c.cep||''}"></div><div class="field"><label>Cidade/UF</label><input id="c_cidade" value="${c.cidade||''}"></div></div><div class="field"><label>Endereço completo</label><input id="c_end" value="${c.end||''}"></div><div class="field"><label>Observações</label><textarea id="c_obs">${c.obs||''}</textarea></div><div class="actions"><button class="btn goldbtn" onclick="saveCliente('${id||''}')">Salvar</button></div>`)}
function saveCliente(id){let obj={id:id||uid(),nome:$('c_nome').value,cpf:$('c_cpf').value,whats:$('c_whats').value,email:$('c_email').value,cep:$('c_cep').value,cidade:$('c_cidade').value,end:$('c_end').value,obs:$('c_obs').value}; if(!obj.nome)return alert('Informe o nome.'); upsert('clientes',obj); closeM(); save()}
function funcionarios(){let rows=st.funcionarios.map(f=>`<tr><td><b>${f.nome}</b></td><td>${f.cargo||'—'}</td><td>${f.whats||'—'}</td><td>${f.email||'—'}</td><td>${f.ativo?'Ativo':'Inativo'}</td><td><button class="btn sm" onclick="openFunc('${f.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('funcionarios','${f.id}')">Excluir</button></td></tr>`).join('');$('p-funcionarios').innerHTML=`<div class="card"><div class="head"><h3>Funcionários</h3><button class="btn goldbtn" onclick="openFunc()">+ Novo funcionário</button></div><table class="table"><thead><tr><th>Nome</th><th>Cargo/Função</th><th>WhatsApp</th><th>E-mail</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="6" class="empty">Nenhum funcionário cadastrado.</td></tr>'}</tbody></table></div>`}
function openFunc(id){let f=st.funcionarios.find(x=>x.id==id)||{};modal(`<div class="mhead"><h3>${id?'Editar':'Novo'} funcionário</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Nome *</label><input id="f_nome" value="${f.nome||''}"></div><div class="field"><label>Cargo/Função</label><input id="f_cargo" value="${f.cargo||'Mecânico'}"></div><div class="field"><label>WhatsApp</label><input id="f_whats" value="${f.whats||''}"></div><div class="field"><label>E-mail</label><input id="f_email" value="${f.email||''}"></div><div class="field"><label>CPF</label><input id="f_cpf" value="${f.cpf||''}"></div><div class="field"><label>Status</label><select id="f_ativo"><option value="1">Ativo</option><option value="0">Inativo</option></select></div></div><div class="field"><label>Observações</label><textarea id="f_obs">${f.obs||''}</textarea></div><div class="actions"><button class="btn goldbtn" onclick="saveFunc('${id||''}')">Salvar funcionário</button></div>`); $('f_ativo').value=f.ativo===false?'0':'1'}
function saveFunc(id){let obj={id:id||uid(),nome:$('f_nome').value,cargo:$('f_cargo').value,whats:$('f_whats').value,email:$('f_email').value,cpf:$('f_cpf').value,ativo:$('f_ativo').value=='1',obs:$('f_obs').value}; if(!obj.nome)return alert('Informe o nome do funcionário.'); upsert('funcionarios',obj); closeM(); save()}function maoObraPage(){let rows=(st.maoObra||[]).map(m=>`<tr><td><b>${m.nome}</b></td><td>${m.cat||'—'}</td><td>${money(m.valor)}</td><td>${m.ativo?'Ativo':'Inativo'}</td><td><button class="btn sm" onclick="openMaoObra('${m.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('maoObra','${m.id}')">Excluir</button></td></tr>`).join('');$('p-maoobra').innerHTML=`<div class="card"><div class="head"><div><h3>Cadastro de Mão de Obra</h3><p style="color:var(--mut);margin:4px 0 0">Cadastre serviços com valor padrão para usar rapidamente dentro da OS.</p></div><button class="btn goldbtn" onclick="openMaoObra()">+ Nova mão de obra</button></div><table class="table"><thead><tr><th>Serviço</th><th>Categoria</th><th>Valor padrão</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="5" class="empty">Nenhuma mão de obra cadastrada.</td></tr>'}</tbody></table></div>`}
function openMaoObra(id){let m=(st.maoObra||[]).find(x=>x.id==id)||{};modal(`<div class="mhead"><h3>${id?'Editar':'Nova'} mão de obra</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Nome do serviço *</label><input id="mo_nome" value="${m.nome||''}" placeholder="Ex: Revisão completa"></div><div class="field"><label>Categoria</label><input id="mo_cat" value="${m.cat||''}" placeholder="Ex: Freio, Câmbio, Geral"></div><div class="field"><label>Valor padrão</label><input id="mo_valor" type="number" step="0.01" value="${m.valor||0}"></div><div class="field"><label>Status</label><select id="mo_ativo"><option value="1">Ativo</option><option value="0">Inativo</option></select></div></div><div class="field"><label>Observações</label><textarea id="mo_obs">${m.obs||''}</textarea></div><div class="actions"><button class="btn goldbtn" onclick="saveMaoObra('${id||''}')">Salvar mão de obra</button></div>`);$('mo_ativo').value=m.ativo===false?'0':'1'}
function saveMaoObra(id){if(!st.maoObra)st.maoObra=[];let obj={id:id||uid(),nome:$('mo_nome').value,cat:$('mo_cat').value,valor:n($('mo_valor').value),ativo:$('mo_ativo').value=='1',obs:$('mo_obs').value};if(!obj.nome)return alert('Informe o nome do serviço.');upsert('maoObra',obj);closeM();save()}

function estoque(){let rows=st.estoque.map(e=>`<tr><td><b>${e.desc}</b></td><td>${e.cod||'—'}</td><td>${e.cat||'—'}</td><td>${e.qtd}</td><td>${e.min}</td><td>${money(e.custo)}</td><td>${money(e.venda)}</td><td><button class="btn sm" onclick="openEst('${e.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('estoque','${e.id}')">Excluir</button></td></tr>`).join('');$('p-estoque').innerHTML=`<div class="card"><div class="head"><h3>Estoque</h3><button class="btn goldbtn" onclick="openEst()">+ Produto/peça</button></div><table class="table"><thead><tr><th>Descrição</th><th>Código</th><th>Categoria</th><th>Qtd</th><th>Mín.</th><th>Custo</th><th>Venda</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="8" class="empty">Nenhum item.</td></tr>'}</tbody></table></div>`}
function openEst(id){let e=st.estoque.find(x=>x.id==id)||{};modal(`<div class="mhead"><h3>Produto/peça</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form3"><div class="field"><label>Descrição *</label><input id="e_desc" value="${e.desc||''}"></div><div class="field"><label>Código</label><input id="e_cod" value="${e.cod||''}"></div><div class="field"><label>Categoria</label><input id="e_cat" value="${e.cat||''}"></div><div class="field"><label>Qtd</label><input id="e_qtd" type="number" value="${e.qtd||0}"></div><div class="field"><label>Mínimo</label><input id="e_min" type="number" value="${e.min||1}"></div><div class="field"><label>Fornecedor</label><input id="e_forn" value="${e.forn||''}"></div><div class="field"><label>Custo</label><input id="e_custo" type="number" step="0.01" value="${e.custo||0}"></div><div class="field"><label>Venda</label><input id="e_venda" type="number" step="0.01" value="${e.venda||0}"></div></div><div class="actions"><button class="btn goldbtn" onclick="saveEst('${id||''}')">Salvar</button></div>`)}
function saveEst(id){let obj={id:id||uid(),desc:$('e_desc').value,cod:$('e_cod').value,cat:$('e_cat').value,qtd:n($('e_qtd').value),min:n($('e_min').value),forn:$('e_forn').value,custo:n($('e_custo').value),venda:n($('e_venda').value)}; if(!obj.desc)return alert('Informe a descrição.'); upsert('estoque',obj); closeM(); save()}
function pecasHTML(pecas=[]){let opts=st.estoque.map(e=>`<option value="${e.id}">${e.desc} — estoque ${e.qtd} — ${money(e.venda)}</option>`).join('');return `<div id="pecasBox">${pecas.map((p,i)=>pecaLine(p,i)).join('')}</div><button class="btn sm" type="button" onclick="addPecaLine()">+ Adicionar peça do estoque</button><template id="pecaTpl"><div class="lineitem"><select class="p_prod" onchange="fillPeca(this)"><option value="">Selecione...</option>${opts}</select><input class="p_qtd" type="number" min="1" value="1"><input class="p_preco" type="number" step="0.01" value="0"><input class="p_nome" placeholder="Nome" readonly><button class="btn redbtn sm" type="button" onclick="this.parentElement.remove()">X</button></div></template>`}
function pecaLine(p){let opts=st.estoque.map(e=>`<option value="${e.id}" ${p.prodId==e.id?'selected':''}>${e.desc} — estoque ${e.qtd} — ${money(e.venda)}</option>`).join('');return `<div class="lineitem"><select class="p_prod" onchange="fillPeca(this)"><option value="">Selecione...</option>${opts}</select><input class="p_qtd" type="number" min="1" value="${p.qtd||1}"><input class="p_preco" type="number" step="0.01" value="${p.preco||0}"><input class="p_nome" value="${p.nome||''}" readonly><button class="btn redbtn sm" type="button" onclick="this.parentElement.remove()">X</button></div>`}
function addPecaLine(){let t=$('pecaTpl').innerHTML;$('pecasBox').insertAdjacentHTML('beforeend',t)}function fillPeca(sel){let e=st.estoque.find(x=>x.id==sel.value),row=sel.parentElement;if(e){row.querySelector('.p_preco').value=e.venda;row.querySelector('.p_nome').value=e.desc}}
function collectPecas(){return [...document.querySelectorAll('#pecasBox .lineitem')].map(r=>{let id=r.querySelector('.p_prod').value,e=st.estoque.find(x=>x.id==id);return {prodId:id,nome:r.querySelector('.p_nome').value||(e?e.desc:''),qtd:n(r.querySelector('.p_qtd').value),preco:n(r.querySelector('.p_preco').value)}}).filter(x=>x.prodId&&x.qtd>0)}
function maoHTML(mao=[]){let opts=(st.maoObra||[]).filter(x=>x.ativo!==false).map(m=>`<option value="${m.id}">${m.nome} — ${money(m.valor)}</option>`).join('');return `<div class="toolbar" style="margin-bottom:10px"><select id="mao_select"><option value="">Selecionar mão de obra cadastrada...</option>${opts}</select><button class="btn sm" type="button" onclick="addMaoCadastrada()">+ Usar serviço</button><button class="btn sm" type="button" onclick="addMaoLine()">+ Serviço manual</button></div><div id="maoBox">${mao.map(m=>`<div class="lineitem" style="grid-template-columns:2fr 1fr auto"><input class="m_desc" value="${m.desc||m.nome||''}" placeholder="Ex: Regulagem de freio"><input class="m_valor" type="number" step="0.01" value="${m.valor||0}"><button class="btn redbtn sm" onclick="this.parentElement.remove()">X</button></div>`).join('')}</div>`}
function addMaoCadastrada(){let id=$('mao_select').value;if(!id)return alert('Selecione uma mão de obra cadastrada.');let m=(st.maoObra||[]).find(x=>x.id==id);if(!m)return;addMaoLine(m.nome,m.valor)}
function addMaoLine(desc='',valor=0){ $('maoBox').insertAdjacentHTML('beforeend',`<div class="lineitem" style="grid-template-columns:2fr 1fr auto"><input class="m_desc" value="${desc}" placeholder="Ex: Revisão completa"><input class="m_valor" type="number" step="0.01" value="${valor}"><button class="btn redbtn sm" onclick="this.parentElement.remove()">X</button></div>`)}function collectMao(){return [...document.querySelectorAll('#maoBox .lineitem')].map(r=>({desc:r.querySelector('.m_desc').value,valor:n(r.querySelector('.m_valor').value)})).filter(x=>x.desc||x.valor)}
function osPage(){let rows=st.os.slice().reverse().map(o=>`<tr><td><b>#${o.num}</b></td><td>${br(o.data)}</td><td>${o.cliente}</td><td>${o.bike}</td><td>${o.funcionario||'—'}</td><td>${money(calcOS(o).total)}</td><td>${statusBadge(o.status)}</td><td><button class="btn sm" onclick="openOS('${o.id}')">Editar</button> <button class="btn sm" onclick="printOS('${o.id}')">PDF/Imprimir</button> <button class="btn sm" onclick="enviarOrcamentoWhats('${o.id}')">WhatsApp</button> <button class="btn redbtn sm" onclick="del('os','${o.id}')">Excluir</button></td></tr>`).join('');$('p-os').innerHTML=`<div class="card"><div class="head"><h3>Ordens de Serviço</h3><button class="btn goldbtn" onclick="openOS()">+ Nova OS</button></div><table class="table"><thead><tr><th>OS</th><th>Data</th><th>Cliente</th><th>Bike</th><th>Funcionário</th><th>Total</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="8" class="empty">Nenhuma OS.</td></tr>'}</tbody></table></div>`}
function openOS(id){let o=st.os.find(x=>x.id==id)||{data:today(),status:'Aberta',pecas:[],mao:[]};let cli=st.clientes.map(c=>`<option ${o.cliente==c.nome?'selected':''}>${c.nome}</option>`).join(''), funcs=st.funcionarios.filter(f=>f.ativo!==false).map(f=>`<option value="${f.id}" ${o.funcionarioId==f.id?'selected':''}>${f.nome} — ${f.cargo||'Funcionário'}</option>`).join('');modal(`<div class="mhead"><h3>${id?'Editar':'Nova'} OS</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form3"><div class="field"><label>Cliente *</label><select id="o_cli"><option value="">Selecione...</option>${cli}</select></div><div class="field"><label>Funcionário responsável</label><select id="o_func"><option value="">Selecione quem fez o serviço...</option>${funcs}</select></div><div class="field"><label>Data</label><input id="o_data" type="date" value="${o.data||today()}"></div><div class="field"><label>Bike/equipamento *</label><input id="o_bike" value="${o.bike||''}"></div><div class="field"><label>Status</label><select id="o_status"><option>Aberta</option><option>Aguardando aprovação</option><option>Em execução</option><option>Pronta para retirada</option><option>Faturada</option><option>Cancelada</option></select></div><div class="field"><label>Desconto</label><input id="o_desc" type="number" step="0.01" value="${o.desc||0}"></div></div><div class="field"><label>Defeito relatado</label><input id="o_def" value="${o.defeito||''}"></div><div class="card"><h3>Peças usadas na OS</h3>${pecasHTML(o.pecas||[])}</div><div class="card"><h3>Mão de obra</h3>${maoHTML(o.mao||[])}</div><div class="field"><label>Observações</label><textarea id="o_obs">${o.obs||''}</textarea></div><div class="notice">A baixa no estoque será feita quando salvar a OS como <b>Pronta para retirada</b>. O pagamento só entra na aba <b>Vendas</b>, quando o cliente vier pagar.</div><div class="actions"><button class="btn goldbtn" onclick="saveOS('${id||''}')">Salvar OS</button></div>`);$('o_status').value=o.status||'Aberta'}
function saveOS(id){let old=st.os.find(x=>x.id==id),func=st.funcionarios.find(f=>f.id==$('o_func').value);let obj={id:id||uid(),num:old?old.num:st.seqOS++,data:$('o_data').value,cliente:$('o_cli').value,bike:$('o_bike').value,defeito:$('o_def').value,funcionarioId:$('o_func').value,funcionario:func?func.nome:'',status:$('o_status').value,desc:n($('o_desc').value),pecas:collectPecas(),mao:collectMao(),obs:$('o_obs').value,baixouEstoque:old?!!old.baixouEstoque:false}; if(!obj.cliente||!obj.bike)return alert('Informe cliente e bike.'); if(obj.status=='Pronta para retirada'&&!obj.baixouEstoque){for(let p of obj.pecas){let e=st.estoque.find(x=>x.id==p.prodId); if(e){if(n(e.qtd)<n(p.qtd))return alert('Estoque insuficiente para: '+e.desc); e.qtd-=n(p.qtd)}} obj.baixouEstoque=true} upsert('os',obj); closeM(); save()}
function vendas(){let prontas=st.os.filter(o=>o.status=='Pronta para retirada').map(o=>`<tr><td>#${o.num}</td><td>${o.cliente}</td><td>${o.funcionario||'—'}</td><td>${money(calcOS(o).total)}</td><td><button class="btn goldbtn sm" onclick="openPay('${o.id}')">Receber / Faturar</button></td></tr>`).join('');let vend=st.vendas.slice().reverse().map(v=>`<tr><td>#${v.num}</td><td>${br(v.data)}</td><td>${v.cliente}</td><td>${v.origem||'Venda rápida'}</td><td>${v.forma}</td><td>${money(v.total)}</td><td>${v.status||'Recebida'}</td><td><button class="btn sm" onclick="printRec('${v.id}')">Recibo</button></td></tr>`).join('');$('p-vendas').innerHTML=`<div class="grid2"><div class="card"><div class="head"><h3>OS prontas aguardando pagamento</h3></div><table class="table"><thead><tr><th>OS</th><th>Cliente</th><th>Funcionário</th><th>Total</th><th></th></tr></thead><tbody>${prontas||'<tr><td colspan="5" class="empty">Nenhuma OS pronta para faturar.</td></tr>'}</tbody></table></div><div class="card"><div class="head"><h3>Venda rápida</h3><button class="btn goldbtn" onclick="openVendaRapida()">+ Nova venda</button></div><div class="notice">Agora a venda pode ser à vista, parcial, parcelada ou <b>a prazo</b>. Quando for a prazo, o sistema gera automaticamente contas a receber com vencimento.</div></div></div><div class="card"><h3>Histórico de vendas</h3><table class="table"><thead><tr><th>Venda</th><th>Data</th><th>Cliente</th><th>Origem</th><th>Pagamento</th><th>Total</th><th>Status</th><th></th></tr></thead><tbody>${vend||'<tr><td colspan="8" class="empty">Nenhuma venda.</td></tr>'}</tbody></table></div>`}
function payHTML(total){return `<div class="form3"><div class="field"><label>Forma de pagamento</label><select id="pay_forma" onchange="payChange()"><option>PIX</option><option>Dinheiro</option><option>Débito</option><option>Crédito 1x</option><option>Crédito Parcelado</option><option>Transferência</option><option>Misto</option><option>A prazo</option><option>Parcial</option></select></div><div class="field"><label>Total</label><input id="pay_total" type="number" step="0.01" value="${Number(total).toFixed(2)}"></div><div class="field"><label>Observação</label><input id="pay_obs" placeholder="Ex: 3x, entrada + restante..."></div></div><div id="mix" style="display:none" class="card"><h3>Pagamento misto</h3><div class="form3"><input id="mix_pix" type="number" step="0.01" placeholder="PIX"><input id="mix_din" type="number" step="0.01" placeholder="Dinheiro"><input id="mix_card" type="number" step="0.01" placeholder="Cartão"></div></div><div id="prazo" style="display:none" class="card"><h3>Venda a prazo / parcelamento</h3><div class="form3"><div class="field"><label>Entrada recebida agora</label><input id="pay_entrada" type="number" step="0.01" value="0"></div><div class="field"><label>Nº de parcelas</label><input id="pay_parcelas" type="number" min="1" value="1"></div><div class="field"><label>Primeiro vencimento</label><input id="pay_venc" type="date" value="${addDays(today(),30)}"></div></div><div class="notice">O saldo em aberto será lançado automaticamente em <b>Contas a Receber</b>. Multa e juros são calculados pelas configurações do sistema quando passar do vencimento.</div></div>`}
function payChange(){let f=$('pay_forma').value;$('mix').style.display=f=='Misto'?'block':'none';$('prazo').style.display=(f=='A prazo'||f=='Parcial'||f=='Crédito Parcelado')?'block':'none'}
function openPay(id){let o=st.os.find(x=>x.id==id),t=calcOS(o).total;modal(`<div class="mhead"><h3>Receber OS #${o.num}</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="notice"><b>Cliente:</b> ${o.cliente}<br><b>Funcionário:</b> ${o.funcionario||'—'}<br><b>Total:</b> ${money(t)}</div>${payHTML(t)}<div class="actions"><button class="btn goldbtn" onclick="receberOS('${id}')">Confirmar recebimento</button></div>`)}
function gerarContasReceber(venda,total,entrada,parcelas,venc1){let saldo=Math.max(0,n(total)-n(entrada));if(saldo<=0)return;parcelas=Math.max(1,parseInt(parcelas||1));let val=saldo/parcelas;for(let i=0;i<parcelas;i++){st.contas.push({id:uid(),tipo:'A Receber',cliente:venda.cliente,venc:addDays(venc1||addDays(today(),30),30*i),valor:val,valorOriginal:val,desc:`${venda.origem||'Venda'} — parcela ${i+1}/${parcelas} — ${venda.cliente}`,status:'Aberto',vendaId:venda.id})}}
function receberOS(id){let o=st.os.find(x=>x.id==id),total=n($('pay_total').value),forma=$('pay_forma').value,obs=$('pay_obs').value,mix=null,entrada=total,status='Recebida';if(forma=='Misto'){mix={pix:n($('mix_pix').value),dinheiro:n($('mix_din').value),cartao:n($('mix_card').value)};if(Math.abs((mix.pix+mix.dinheiro+mix.cartao)-total)>0.01)return alert('A soma do pagamento misto precisa fechar com o total.')}if(['A prazo','Parcial','Crédito Parcelado'].includes(forma)){entrada=n($('pay_entrada').value);status=entrada>0?'Parcial / a receber':'A receber'}let v={id:uid(),num:st.seqVenda++,data:today(),cliente:o.cliente,origem:'OS #'+o.num,osId:o.id,funcionario:o.funcionario,funcionarioId:o.funcionarioId,total,forma,obs,mix,status,entrada,itens:[...(o.pecas||[]),...(o.mao||[]).map(m=>({nome:m.desc,qtd:1,preco:m.valor}))]};st.vendas.push(v);o.status=entrada>=total?'Faturada':'Pronta para retirada';o.pagamento={forma,total,obs,mix,data:today(),vendaId:v.id,status};if(entrada>0)addCaixa('Entrada',entrada,'Entrada recebida '+v.origem+' — '+o.cliente,'OS / Serviço');if(entrada<total)gerarContasReceber(v,total,entrada,$('pay_parcelas')?.value,$('pay_venc')?.value);closeM();save()}
function openVendaRapida(){modal(`<div class="mhead"><h3>Venda rápida</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="field"><label>Cliente</label><input id="vr_cli" placeholder="Consumidor"></div><div class="card"><h3>Produtos</h3>${pecasHTML([])}</div>${payHTML(0)}<div class="actions"><button class="btn goldbtn" onclick="saveVendaRapida()">Finalizar venda</button></div>`)}
function saveVendaRapida(){let itens=collectPecas(),total=itens.reduce((a,i)=>a+i.qtd*i.preco,0);if(!itens.length)return alert('Adicione produtos.');for(let p of itens){let e=st.estoque.find(x=>x.id==p.prodId);if(e){if(e.qtd<p.qtd)return alert('Estoque insuficiente para '+e.desc);e.qtd-=p.qtd}}let forma=$('pay_forma').value,entrada=total,status='Recebida';if(['A prazo','Parcial','Crédito Parcelado'].includes(forma)){entrada=n($('pay_entrada').value);status=entrada>0?'Parcial / a receber':'A receber'}let v={id:uid(),num:st.seqVenda++,data:today(),cliente:$('vr_cli').value||'Consumidor',origem:'Venda rápida',total,forma,obs:$('pay_obs').value,status,entrada,itens};st.vendas.push(v);if(entrada>0)addCaixa('Entrada',entrada,'Venda rápida #'+v.num,'Venda Produto');if(entrada<total)gerarContasReceber(v,total,entrada,$('pay_parcelas')?.value,$('pay_venc')?.value);closeM();save()}
function caixa(){let rows=st.caixa.slice().reverse().map(x=>`<tr><td>${br(x.data)} ${x.hora}</td><td><span class="badge ${x.tipo=='Entrada'?'b3':'b5'}">${x.tipo}</span></td><td>${x.desc}</td><td>${x.cat}</td><td class="${x.tipo=='Entrada'?'green':'red'}"><b>${money(x.valor)}</b></td></tr>`).join('');$('p-caixa').innerHTML=`<div class="card"><div class="head"><h3>Caixa e fluxo</h3><button class="btn goldbtn" onclick="openCx()">+ Lançamento</button></div><table class="table"><thead><tr><th>Data</th><th>Tipo</th><th>Descrição</th><th>Categoria</th><th>Valor</th></tr></thead><tbody>${rows||'<tr><td colspan="5" class="empty">Nenhum lançamento.</td></tr>'}</tbody></table></div>`}function addCaixa(tipo,valor,desc,cat){st.caixa.push({id:uid(),tipo,valor:n(valor),desc,cat,data:today(),hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})})}function openCx(){modal(`<div class="mhead"><h3>Novo lançamento</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Tipo</label><select id="cx_tipo"><option>Entrada</option><option>Saída</option></select></div><div class="field"><label>Valor</label><input id="cx_valor" type="number" step="0.01"></div><div class="field"><label>Categoria</label><input id="cx_cat" value="Outro"></div><div class="field"><label>Descrição</label><input id="cx_desc"></div></div><div class="actions"><button class="btn goldbtn" onclick="addCaixa($('cx_tipo').value,$('cx_valor').value,$('cx_desc').value,$('cx_cat').value);closeM();save()">Salvar</button></div>`)}
function contas(){let filt=$('ct_mes')?.value||'';let lista=st.contas.slice().sort((a,b)=>(a.venc||'').localeCompare(b.venc||''));if(filt)lista=lista.filter(c=>monthKey(c.venc)==filt);let rows=lista.map(c=>`<tr><td>${br(c.venc)}</td><td>${c.tipo}</td><td>${c.cliente||'—'}</td><td>${c.desc}</td><td>${money(c.valorOriginal||c.valor)}</td><td>${money(jurosConta(c))}</td><td><b>${money(totalConta(c))}</b></td><td>${statusConta(c)}</td><td><button class="btn sm" onclick="baixarConta('${c.id}')">Baixar</button> <button class="btn redbtn sm" onclick="del('contas','${c.id}')">Excluir</button></td></tr>`).join('');let rec=lista.filter(c=>c.tipo=='A Receber'&&c.status!='Pago').reduce((a,c)=>a+totalConta(c),0),pag=lista.filter(c=>c.tipo=='A Pagar'&&c.status!='Pago').reduce((a,c)=>a+totalConta(c),0);$('p-contas').innerHTML=`<div class="grid3"><div class="metric"><div class="label">A receber aberto</div><div class="value green">${money(rec)}</div></div><div class="metric"><div class="label">A pagar aberto</div><div class="value red">${money(pag)}</div></div><div class="metric"><div class="label">Resultado</div><div class="value ${rec-pag>=0?'green':'red'}">${money(rec-pag)}</div></div></div><div class="card"><div class="head"><h3>Contas a pagar e receber</h3><div class="toolbar"><input id="ct_mes" type="month" value="${filt}" onchange="contas()"><button class="btn goldbtn" onclick="openConta()">+ Nova conta</button><button class="btn" onclick="openRecorrente()">+ Conta mensal</button><button class="btn" onclick="exportContasCSV()">Exportar CSV</button></div></div><table class="table"><thead><tr><th>Venc.</th><th>Tipo</th><th>Cliente</th><th>Descrição</th><th>Original</th><th>Juros/multa</th><th>Total</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="9" class="empty">Nenhuma conta.</td></tr>'}</tbody></table></div><div class="card"><h3>Contas mensais recorrentes</h3><table class="table"><thead><tr><th>Dia</th><th>Tipo</th><th>Descrição</th><th>Valor</th><th>Status</th></tr></thead><tbody>${(st.recorrentes||[]).map(r=>`<tr><td>${r.dia}</td><td>${r.tipo}</td><td>${r.desc}</td><td>${money(r.valor)}</td><td>${r.ativo?'Ativa':'Inativa'}</td></tr>`).join('')||'<tr><td colspan="5" class="empty">Nenhuma conta mensal.</td></tr>'}</tbody></table></div>`}
function openConta(){modal(`<div class="mhead"><h3>Nova conta</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Tipo</label><select id="ct_tipo"><option>A Pagar</option><option>A Receber</option></select></div><div class="field"><label>Vencimento</label><input id="ct_venc" type="date" value="${today()}"></div><div class="field"><label>Valor</label><input id="ct_valor" type="number" step="0.01"></div><div class="field"><label>Cliente</label><input id="ct_cliente" placeholder="Opcional"></div></div><div class="field"><label>Descrição</label><input id="ct_desc"></div><div class="actions"><button class="btn goldbtn" onclick="st.contas.push({id:uid(),tipo:$('ct_tipo').value,venc:$('ct_venc').value,valor:n($('ct_valor').value),valorOriginal:n($('ct_valor').value),cliente:$('ct_cliente').value,desc:$('ct_desc').value,status:'Aberto'});closeM();save()">Salvar</button></div>`)}
function openRecorrente(){modal(`<div class="mhead"><h3>Conta mensal recorrente</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Tipo</label><select id="rc_tipo"><option>A Pagar</option><option>A Receber</option></select></div><div class="field"><label>Dia do vencimento</label><input id="rc_dia" type="number" min="1" max="28" value="5"></div><div class="field"><label>Valor</label><input id="rc_valor" type="number" step="0.01"></div><div class="field"><label>Descrição</label><input id="rc_desc" placeholder="Aluguel, internet, energia..."></div></div><div class="actions"><button class="btn goldbtn" onclick="st.recorrentes.push({id:uid(),tipo:$('rc_tipo').value,dia:$('rc_dia').value,valor:n($('rc_valor').value),desc:$('rc_desc').value,ativo:true});gerarRecorrentes();closeM();save()">Salvar e gerar mês atual</button></div>`)}
function baixarConta(id){let c=st.contas.find(x=>x.id==id);if(!c)return;c.status='Pago';c.valorPago=totalConta(c);c.dataPgto=today();addCaixa(c.tipo=='A Receber'?'Entrada':'Saída',c.valorPago,c.desc,c.tipo);save()}
function exportContasCSV(){csvDownload('contas_maybike.csv', [['Vencimento','Tipo','Cliente','Descrição','Valor original','Juros/multa','Total','Status'],...st.contas.map(c=>[br(c.venc),c.tipo,c.cliente||'',c.desc,money(c.valorOriginal||c.valor),money(jurosConta(c)),money(totalConta(c)),c.status])])}

function relatorios(){let ent=st.caixa.filter(x=>x.tipo=='Entrada').reduce((a,b)=>a+n(b.valor),0),sai=st.caixa.filter(x=>x.tipo=='Saída').reduce((a,b)=>a+n(b.valor),0),cost=st.estoque.reduce((a,e)=>a+n(e.qtd)*n(e.custo),0);let rec=contasAbertas('A Receber').reduce((a,c)=>a+totalConta(c),0),pag=contasAbertas('A Pagar').reduce((a,c)=>a+totalConta(c),0),res=rec-pag;let funcs=st.funcionarios.map(f=>{let q=st.os.filter(o=>o.funcionarioId==f.id).length, fat=st.vendas.filter(v=>v.funcionarioId==f.id||v.funcionario==f.nome).reduce((a,v)=>a+n(v.total),0), com=comissaoFunc(f);return `<tr><td>${f.nome}</td><td>${f.cargo||'—'}</td><td>${q}</td><td>${money(fat)}</td><td>${money(com)}</td></tr>`}).join('');let rank=servicoRanking().map(([s,q],i)=>`<tr><td>${i+1}º</td><td>${s}</td><td>${q}</td></tr>`).join('');let months={};st.vendas.forEach(v=>{let k=monthKey(v.data);months[k]=months[k]||{fat:0,lucro:0};months[k].fat+=n(v.total);months[k].lucro+=lucroVenda(v)});let mesRows=Object.entries(months).sort().reverse().map(([k,v])=>`<tr><td>${k}</td><td>${money(v.fat)}</td><td>${money(v.lucro)}</td></tr>`).join('');$('p-relatorios').innerHTML=`<div class="grid3"><div class="metric"><div class="label">A receber aberto</div><div class="value green">${money(rec)}</div></div><div class="metric"><div class="label">A pagar aberto</div><div class="value red">${money(pag)}</div></div><div class="metric"><div class="label">Resultado por contas</div><div class="value ${res>=0?'green':'red'}">${res>=0?'Lucro ':'Prejuízo '}${money(Math.abs(res))}</div></div></div><div class="grid3"><div class="metric"><div class="label">Entradas no caixa</div><div class="value green">${money(ent)}</div></div><div class="metric"><div class="label">Saídas no caixa</div><div class="value red">${money(sai)}</div></div><div class="metric"><div class="label">Saldo caixa</div><div class="value ${ent-sai>=0?'green':'red'}">${money(ent-sai)}</div></div></div><div class="toolbar" style="margin-bottom:14px"><button class="btn" onclick="exportRelatoriosCSV()">Exportar relatório CSV</button></div><div class="grid2"><div class="card"><h3>Relatório de comissão</h3><table class="table"><thead><tr><th>Funcionário</th><th>Cargo</th><th>OS</th><th>Faturamento</th><th>Comissão estimada</th></tr></thead><tbody>${funcs||'<tr><td colspan="5" class="empty">Sem funcionários.</td></tr>'}</tbody></table></div><div class="card"><h3>Ranking de serviços mais executados</h3><table class="table"><thead><tr><th>#</th><th>Serviço</th><th>Qtd.</th></tr></thead><tbody>${rank||'<tr><td colspan="3" class="empty">Sem serviços.</td></tr>'}</tbody></table></div></div><div class="grid2"><div class="card"><h3>Faturamento mês a mês</h3><table class="table"><thead><tr><th>Mês</th><th>Faturamento</th><th>Lucro estimado</th></tr></thead><tbody>${mesRows||'<tr><td colspan="3" class="empty">Sem vendas.</td></tr>'}</tbody></table></div><div class="card"><h3>Resumo geral</h3><p>Clientes: <b>${st.clientes.length}</b></p><p>Funcionários: <b>${st.funcionarios.length}</b></p><p>Mão de obra cadastrada: <b>${(st.maoObra||[]).length}</b></p><p>OS: <b>${st.os.length}</b></p><p>Vendas: <b>${st.vendas.length}</b></p><p>Custo em estoque: <b>${money(cost)}</b></p></div></div>`}
function exportRelatoriosCSV(){csvDownload('relatorio_maybike.csv', [['Tipo','Descrição','Valor'],['Caixa','Entradas',money(st.caixa.filter(x=>x.tipo=='Entrada').reduce((a,b)=>a+n(b.valor),0))],['Caixa','Saídas',money(st.caixa.filter(x=>x.tipo=='Saída').reduce((a,b)=>a+n(b.valor),0))],['Contas','A receber',money(contasAbertas('A Receber').reduce((a,c)=>a+totalConta(c),0))],['Contas','A pagar',money(contasAbertas('A Pagar').reduce((a,c)=>a+totalConta(c),0))],...servicoRanking().map(([s,q])=>['Ranking serviço',s,q])])}



async function addUserSecure(){let login=$('u_login').value.trim(), senha=$('u_senha').value, nome=$('u_nome').value.trim(), perfil=$('u_perfil').value;if(!login||!senha)return alert('Informe login e senha.');if(st.users.some(u=>u.u==login))return alert('Esse login já existe.');st.users.push({u:login,pHash:await hashPass(senha),nome,perfil});save();config();alert('Usuário criado com senha criptografada no cadastro local.')}async function changeAdminPass(){let p=$('newpass').value;if(!p)return alert('Digite a nova senha.');st.users[0].pHash=await hashPass(p);delete st.users[0].p;save();alert('Senha admin alterada com criptografia local.');config()}
function regrasFirebase(){modal(`<div class="mhead"><h3>Regras recomendadas do Firebase</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="notice">Para uso real, o ideal é ativar Firebase Authentication. Como este sistema é HTML simples, use essas regras abertas apenas durante testes. Para operação definitiva, recomendo migrar o login para Firebase Auth.</div><pre style="white-space:pre-wrap;background:#080a0e;border:1px solid var(--line);border-radius:14px;padding:14px;color:#ffe8a4">rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {
    match /{document=**} {
      allow read, write: if request.time < timestamp.date(2026, 12, 31);
    }
  }
}</pre>`) }
function config(){$('p-config').innerHTML=`<div class="card"><h3>Configurações V13</h3><div class="notice"><b>V13 ERP Enterprise May Bike</b> mantém o mesmo Firebase <b>maybike-d8a6d</b> e o mesmo documento de dados. Novas funções: venda a prazo, parcelamento, pagamento parcial, contas mensais, juros/multa configuráveis, comissão, WhatsApp, PDF/impressão e relatórios avançados.</div><div class="toolbar" style="margin-top:14px"><button class="btn goldbtn" onclick="exportData()">Exportar backup JSON</button><label class="btn">Importar backup<input type="file" style="display:none" onchange="importData(this)"></label><button class="btn" onclick="regrasFirebase()">Ver regras Firebase</button><button class="btn redbtn" onclick="if(confirm('Zerar somente o navegador?')){localStorage.removeItem(STORE);location.reload()}">Zerar local</button></div><hr style="border-color:var(--line)"><h3>Juros, multa e comissão</h3><div class="notice">Configure os percentuais conforme orientação do seu contador/advogado. O sistema calcula automaticamente em contas vencidas.</div><div class="form3"><div class="field"><label>Multa por atraso (%)</label><input id="cfg_multa" type="number" step="0.01" value="${st.config.multaPercent}"></div><div class="field"><label>Juros ao mês (%)</label><input id="cfg_juros" type="number" step="0.01" value="${st.config.jurosMesPercent}"></div><div class="field"><label>Comissão mecânico (%)</label><input id="cfg_commec" type="number" step="0.01" value="${st.config.comissaoMecanicoPercent}"></div></div><div class="actions"><button class="btn goldbtn" onclick="st.config.multaPercent=n($('cfg_multa').value);st.config.jurosMesPercent=n($('cfg_juros').value);st.config.comissaoMecanicoPercent=n($('cfg_commec').value);save()">Salvar configurações financeiras</button></div><hr style="border-color:var(--line)"><h3>Usuários e permissões</h3><div class="form3"><input id="u_nome" placeholder="Nome do usuário"><input id="u_login" placeholder="Login"><select id="u_perfil"><option>Administrador</option><option>Mecânico</option><option>Vendedor</option><option>Financeiro</option></select></div><div class="form2"><input id="u_senha" placeholder="Senha"><button class="btn goldbtn" onclick="addUserSecure()">Adicionar usuário</button></div><table class="table"><thead><tr><th>Nome</th><th>Login</th><th>Perfil</th><th></th></tr></thead><tbody>${st.users.map((u,i)=>`<tr><td>${u.nome||u.u}</td><td>${u.u}</td><td>${u.perfil||'Administrador'}</td><td>${i>0?`<button class="btn redbtn sm" onclick="st.users.splice(${i},1);save();config()">Excluir</button>`:'Principal'}</td></tr>`).join('')}</tbody></table><h3>Senha admin</h3><div class="form2"><input id="newpass" placeholder="Nova senha"><button class="btn goldbtn" onclick="changeAdminPass()">Salvar senha</button></div></div>`}

function printOS(id){let o=st.os.find(x=>x.id==id),t=calcOS(o);let cliente=st.clientes.find(c=>c.nome==o.cliente)||{};$('print').innerHTML=`<div style="text-align:center;border-bottom:2px solid #111;padding-bottom:12px"><h1>🚲 May Bike</h1><p>WhatsApp: 42 98842-5435 | E-mail: maybikee@gmail.com</p><h2>ORDEM DE SERVIÇO #${o.num}</h2></div><p><b>Cliente:</b> ${o.cliente} &nbsp; <b>CPF:</b> ${cliente.cpf||'—'}</p><p><b>Endereço:</b> ${cliente.end||'—'} ${cliente.cidade||''}</p><p><b>Funcionário:</b> ${o.funcionario||'—'} &nbsp; <b>Status:</b> ${o.status}</p><p><b>Bike:</b> ${o.bike}</p><p><b>Defeito relatado:</b> ${o.defeito||'—'}</p><table><tr><th>Item</th><th>Qtd</th><th>Valor</th></tr>${(o.pecas||[]).map(p=>`<tr><td>${p.nome}</td><td>${p.qtd}</td><td>${money(p.qtd*p.preco)}</td></tr>`).join('')}${(o.mao||[]).map(m=>`<tr><td>${m.desc}</td><td>1</td><td>${money(m.valor)}</td></tr>`).join('')}<tr><td colspan="2"><b>Desconto</b></td><td>${money(o.desc||0)}</td></tr></table><h2>Total: ${money(t.total)}</h2><p><b>Garantia:</b> 90 dias para mão de obra. Peças seguem garantia do fabricante.</p><br><p>Assinatura cliente: ________________________________</p><p>Assinatura loja: ___________________________________</p>`;window.print()}
function printRec(id){let v=st.vendas.find(x=>x.id==id);$('print').innerHTML=`<div style="text-align:center;border-bottom:2px solid #111;padding-bottom:12px"><h1>🚲 May Bike</h1><p>WhatsApp: 42 98842-5435 | E-mail: maybikee@gmail.com</p><h2>RECIBO #${v.num}</h2></div><p><b>Cliente:</b> ${v.cliente} | <b>Origem:</b> ${v.origem}</p><p><b>Pagamento:</b> ${v.forma} ${v.obs||''}</p><p><b>Status:</b> ${v.status||'Recebida'}</p><h2>Total da venda: ${money(v.total)}</h2><h2>Recebido agora: ${money(v.entrada??v.total)}</h2>`;window.print()}
function enviarOrcamentoWhats(id){let o=st.os.find(x=>x.id==id),cli=st.clientes.find(c=>c.nome==o.cliente)||{},t=calcOS(o);let msg=`Olá, ${o.cliente}! Aqui é da May Bike.\n\nSegue orçamento da sua OS #${o.num}:\nBike: ${o.bike}\nServiços/peças: ${money(t.total)}\nStatus: ${o.status}\n\nWhatsApp May Bike: 42 98842-5435`;window.open(whatsappUrl(msg,cli.whats),'_blank')}

function modal(html){$('modal').innerHTML=html;$('modalbg').classList.add('open')}function closeM(){$('modalbg').classList.remove('open')}window.onclick=e=>{if(e.target==$('modalbg'))closeM()};function upsert(col,obj){let i=st[col].findIndex(x=>x.id==obj.id); if(i>=0)st[col][i]=obj;else st[col].push(obj)}function del(col,id){if(!confirm('Excluir?'))return;st[col]=st[col].filter(x=>x.id!=id);save()}function exportData(){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(st,null,2)],{type:'application/json'}));a.download='backup_maybike_v12.json';a.click()}function importData(inp){let f=inp.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{st=JSON.parse(r.result);saveLocal();save();location.reload()};r.readAsText(f)}


/* ===== V13 ENTERPRISE — Estoque inteligente, bicicletas, fotos, agenda, garantias, CRM e auditoria ===== */
function logAudit(acao,detalhe){try{st.audit=st.audit||[];let u=JSON.parse(sessionStorage.mbUser||'{}');st.audit.unshift({id:uid(),data:new Date().toISOString(),usuario:u.nome||u.u||'Sistema',acao,detalhe});st.audit=st.audit.slice(0,500)}catch(e){}}
function margemCategoria(cat){let c=(st.categoriasMargem||[]).find(x=>(x.cat||'').toLowerCase()==String(cat||'').toLowerCase());return c?n(c.margem):n(st.config.margemPadrao||75)}
function calcProduto(e){let compra=n(e.precoCompra||e.custo),ipi=compra*n(e.ipi)/100,final=compra+ipi+n(e.frete)+n(e.outrosCustos),m=n(e.margem||margemCategoria(e.cat));let vendaSugerida=final*(1+m/100),venda=n(e.venda||vendaSugerida),lucro=venda-final,marginReal=final>0?(lucro/final*100):0;return {ipiValor:ipi,custoReal:final,vendaSugerida,lucro,marginReal}}
function recalcEstModal(){let e={precoCompra:$('e_compra')?.value,ipi:$('e_ipi')?.value,frete:$('e_frete')?.value,outrosCustos:$('e_outros')?.value,margem:$('e_margem')?.value,cat:$('e_cat')?.value,venda:$('e_venda')?.value};let c=calcProduto(e);if($('e_custo_real'))$('e_custo_real').value=c.custoReal.toFixed(2);if($('e_sugerido'))$('e_sugerido').value=c.vendaSugerida.toFixed(2);if($('e_lucro'))$('e_lucro').value=c.lucro.toFixed(2);if($('e_mreal'))$('e_mreal').value=c.marginReal.toFixed(1)+'%'}
function aplicarPrecoSugerido(){if($('e_venda')&&$('e_sugerido')){$('e_venda').value=$('e_sugerido').value;recalcEstModal()}}
function estoque(){let totalCusto=st.estoque.reduce((a,e)=>a+n(e.qtd)*calcProduto(e).custoReal,0),lucroPot=st.estoque.reduce((a,e)=>a+n(e.qtd)*calcProduto(e).lucro,0),crit=st.estoque.filter(e=>n(e.qtd)<=n(e.min)).length;let rows=st.estoque.map(e=>{let c=calcProduto(e);return `<tr><td><b>${e.desc}</b><br><small>${e.forn||''}</small></td><td>${e.cod||'—'}</td><td>${e.cat||'—'}</td><td>${e.qtd}</td><td>${e.min}</td><td>${money(e.precoCompra||e.custo)}</td><td>${n(e.ipi)}%</td><td>${money(c.custoReal)}</td><td>${money(e.venda||c.vendaSugerida)}</td><td class="${c.marginReal<n(st.config.margemMinima)?'red':'green'}">${c.marginReal.toFixed(1)}%</td><td>${money(c.lucro)}</td><td><button class="btn sm" onclick="openEst('${e.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('estoque','${e.id}')">Excluir</button></td></tr>`}).join('');$('p-estoque').innerHTML=`<div class="grid3"><div class="metric"><div class="label">Capital em estoque</div><div class="value gold">${money(totalCusto)}</div></div><div class="metric"><div class="label">Lucro potencial</div><div class="value green">${money(lucroPot)}</div></div><div class="metric"><div class="label">Estoque crítico</div><div class="value red">${crit}</div></div></div><div class="card"><div class="head"><div><h3>Estoque inteligente</h3><p style="color:var(--mut);margin:4px 0 0">Calcula IPI, frete, custo real, margem e preço sugerido.</p></div><button class="btn goldbtn" onclick="openEst()">+ Produto/peça</button></div><table class="table"><thead><tr><th>Descrição</th><th>Código</th><th>Categoria</th><th>Qtd</th><th>Mín.</th><th>Compra</th><th>IPI</th><th>Custo real</th><th>Venda</th><th>Margem</th><th>Lucro un.</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="12" class="empty">Nenhum item.</td></tr>'}</tbody></table></div>`}
function openEst(id){let e=st.estoque.find(x=>x.id==id)||{};let marg=e.margem||margemCategoria(e.cat);modal(`<div class="mhead"><h3>${id?'Editar':'Novo'} produto/peça</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form3"><div class="field"><label>Descrição *</label><input id="e_desc" value="${e.desc||''}"></div><div class="field"><label>Código</label><input id="e_cod" value="${e.cod||''}"></div><div class="field"><label>Categoria</label><input id="e_cat" list="cats" value="${e.cat||''}" oninput="if(!$('e_margem').dataset.manual){$('e_margem').value=margemCategoria(this.value)};recalcEstModal()"><datalist id="cats">${(st.categoriasMargem||[]).map(c=>`<option value="${c.cat}">`).join('')}</datalist></div><div class="field"><label>Qtd</label><input id="e_qtd" type="number" value="${e.qtd||0}"></div><div class="field"><label>Mínimo</label><input id="e_min" type="number" value="${e.min||1}"></div><div class="field"><label>Fornecedor</label><input id="e_forn" value="${e.forn||''}"></div></div><div class="card"><h3>Precificação automática</h3><div class="form3"><div class="field"><label>Preço de compra</label><input id="e_compra" type="number" step="0.01" value="${e.precoCompra||e.custo||0}" oninput="recalcEstModal()"></div><div class="field"><label>IPI (%)</label><input id="e_ipi" type="number" step="0.01" value="${e.ipi||0}" oninput="recalcEstModal()"></div><div class="field"><label>Frete rateado</label><input id="e_frete" type="number" step="0.01" value="${e.frete||0}" oninput="recalcEstModal()"></div><div class="field"><label>Outros custos</label><input id="e_outros" type="number" step="0.01" value="${e.outrosCustos||0}" oninput="recalcEstModal()"></div><div class="field"><label>Margem desejada (%)</label><input id="e_margem" type="number" step="0.01" value="${marg}" oninput="this.dataset.manual=1;recalcEstModal()"></div><div class="field"><label>Custo real</label><input id="e_custo_real" readonly></div><div class="field"><label>Preço sugerido</label><input id="e_sugerido" readonly></div><div class="field"><label>Preço de venda final</label><input id="e_venda" type="number" step="0.01" value="${e.venda||0}" oninput="recalcEstModal()"></div><div class="field"><label>Lucro / Margem real</label><div class="form2" style="gap:6px"><input id="e_lucro" readonly><input id="e_mreal" readonly></div></div></div><button class="btn sm" onclick="aplicarPrecoSugerido()">Usar preço sugerido</button></div><div class="actions"><button class="btn goldbtn" onclick="saveEst('${id||''}')">Salvar produto</button></div>`);recalcEstModal()}
function saveEst(id){let base={precoCompra:n($('e_compra').value),ipi:n($('e_ipi').value),frete:n($('e_frete').value),outrosCustos:n($('e_outros').value),margem:n($('e_margem').value),cat:$('e_cat').value,venda:n($('e_venda').value)};let c=calcProduto(base);let obj={id:id||uid(),desc:$('e_desc').value,cod:$('e_cod').value,cat:$('e_cat').value,qtd:n($('e_qtd').value),min:n($('e_min').value),forn:$('e_forn').value,precoCompra:base.precoCompra,ipi:base.ipi,frete:base.frete,outrosCustos:base.outrosCustos,margem:base.margem,custo:c.custoReal,custoReal:c.custoReal,venda:base.venda||c.vendaSugerida};if(!obj.desc)return alert('Informe a descrição.');upsert('estoque',obj);logAudit(id?'Produto editado':'Produto cadastrado',obj.desc);closeM();save()}
function clientes(){let rows=st.clientes.map(c=>{let bikes=(st.bikes||[]).filter(b=>b.clienteId==c.id).length, aberto=st.contas.filter(x=>x.cliente==c.nome&&x.tipo=='A Receber'&&x.status!='Pago').reduce((a,x)=>a+totalConta(x),0);return `<tr><td><b>${c.nome}</b></td><td>${c.cpf||'—'}</td><td>${c.whats||'—'}</td><td>${c.cidade||'—'}</td><td>${bikes}</td><td class="${aberto>0?'red':'green'}">${money(aberto)}</td><td><button class="btn sm" onclick="openCliente('${c.id}')">Editar</button> <button class="btn sm" onclick="openBike('', '${c.id}')">+ Bike</button> <button class="btn redbtn sm" onclick="del('clientes','${c.id}')">Excluir</button></td></tr>`}).join('');$('p-clientes').innerHTML=`<div class="card"><div class="head"><h3>Clientes</h3><button class="btn goldbtn" onclick="openCliente()">+ Novo cliente</button></div><table class="table"><thead><tr><th>Nome</th><th>CPF</th><th>WhatsApp</th><th>Cidade</th><th>Bikes</th><th>Em aberto</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="7" class="empty">Nenhum cliente.</td></tr>'}</tbody></table></div>`}
function bicicletasPage(){let rows=(st.bikes||[]).map(b=>{let c=st.clientes.find(x=>x.id==b.clienteId)||{};let ultima=ultimaOSBike(b.id);return `<tr><td><b>${b.marca||''} ${b.modelo||''}</b><br><small>${b.cor||''} Aro ${b.aro||''}</small></td><td>${c.nome||'—'}</td><td>${b.quadro||'—'}</td><td>${ultima?br(ultima.data):'—'}</td><td>${b.obs||'—'}</td><td><button class="btn sm" onclick="openBike('${b.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('bikes','${b.id}')">Excluir</button></td></tr>`}).join('');$('p-bicicletas').innerHTML=`<div class="card"><div class="head"><h3>Bicicletas dos clientes</h3><button class="btn goldbtn" onclick="openBike()">+ Nova bicicleta</button></div><table class="table"><thead><tr><th>Bike</th><th>Cliente</th><th>Nº Quadro</th><th>Última OS</th><th>Obs.</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="6" class="empty">Nenhuma bicicleta cadastrada.</td></tr>'}</tbody></table></div>`}
function openBike(id,clienteId=''){let b=(st.bikes||[]).find(x=>x.id==id)||{clienteId};let opts=st.clientes.map(c=>`<option value="${c.id}" ${b.clienteId==c.id?'selected':''}>${c.nome}</option>`).join('');modal(`<div class="mhead"><h3>${id?'Editar':'Nova'} bicicleta</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form3"><div class="field"><label>Cliente *</label><select id="b_cliente"><option value="">Selecione...</option>${opts}</select></div><div class="field"><label>Marca</label><input id="b_marca" value="${b.marca||''}"></div><div class="field"><label>Modelo</label><input id="b_modelo" value="${b.modelo||''}"></div><div class="field"><label>Cor</label><input id="b_cor" value="${b.cor||''}"></div><div class="field"><label>Aro</label><input id="b_aro" value="${b.aro||''}"></div><div class="field"><label>Nº do quadro</label><input id="b_quadro" value="${b.quadro||''}"></div></div><div class="field"><label>Observações</label><textarea id="b_obs">${b.obs||''}</textarea></div><div class="actions"><button class="btn goldbtn" onclick="saveBike('${id||''}')">Salvar bicicleta</button></div>`)}
function saveBike(id){let obj={id:id||uid(),clienteId:$('b_cliente').value,marca:$('b_marca').value,modelo:$('b_modelo').value,cor:$('b_cor').value,aro:$('b_aro').value,quadro:$('b_quadro').value,obs:$('b_obs').value};if(!obj.clienteId)return alert('Selecione o cliente.');upsert('bikes',obj);logAudit(id?'Bike editada':'Bike cadastrada',`${obj.marca} ${obj.modelo}`);closeM();save()}
function ultimaOSBike(bikeId){return st.os.filter(o=>o.bikeId==bikeId).sort((a,b)=>(b.data||'').localeCompare(a.data||''))[0]}
function bikesDoClienteSelect(selId,bikeId){let cli=st.clientes.find(c=>c.nome==$(selId).value);let bikes=(st.bikes||[]).filter(b=>b.clienteId==(cli&&cli.id));let opts=bikes.map(b=>`<option value="${b.id}" ${bikeId==b.id?'selected':''}>${b.marca||''} ${b.modelo||''} ${b.cor||''}</option>`).join('');$('o_bike_sel').innerHTML='<option value="">Digitar manualmente</option>'+opts}
function readImages(input,box){let files=[...input.files].slice(0,4);$(box).innerHTML='Carregando imagens...';Promise.all(files.map(f=>new Promise(res=>{let r=new FileReader();r.onload=()=>res(r.result);r.readAsDataURL(f)}))).then(arr=>{$(box).dataset.photos=JSON.stringify(arr);$(box).innerHTML=arr.map(src=>`<img class="thumb" src="${src}">`).join('')})}
function osPage(){let rows=st.os.slice().reverse().map(o=>`<tr><td><b>#${o.num}</b></td><td>${br(o.data)}</td><td>${o.cliente}</td><td>${o.bike}</td><td>${o.funcionario||'—'}</td><td>${money(calcOS(o).total)}</td><td>${statusBadge(o.status)}</td><td>${o.garantiaAte?br(o.garantiaAte):'—'}</td><td><button class="btn sm" onclick="openOS('${o.id}')">Editar</button> <button class="btn sm" onclick="printOS('${o.id}')">PDF/Imprimir</button> <button class="btn sm" onclick="enviarOrcamentoWhats('${o.id}')">WhatsApp</button> <button class="btn redbtn sm" onclick="del('os','${o.id}')">Excluir</button></td></tr>`).join('');$('p-os').innerHTML=`<div class="card"><div class="head"><h3>Ordens de Serviço</h3><button class="btn goldbtn" onclick="openOS()">+ Nova OS</button></div><table class="table"><thead><tr><th>OS</th><th>Data</th><th>Cliente</th><th>Bike</th><th>Funcionário</th><th>Total</th><th>Status</th><th>Garantia até</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="9" class="empty">Nenhuma OS.</td></tr>'}</tbody></table></div>`}
function openOS(id){let o=st.os.find(x=>x.id==id)||{data:today(),status:'Aberta',pecas:[],mao:[],fotosAntes:[],fotosDepois:[]};let cli=st.clientes.map(c=>`<option ${o.cliente==c.nome?'selected':''}>${c.nome}</option>`).join(''), funcs=st.funcionarios.filter(f=>f.ativo!==false).map(f=>`<option value="${f.id}" ${o.funcionarioId==f.id?'selected':''}>${f.nome} — ${f.cargo||'Funcionário'}</option>`).join('');modal(`<div class="mhead"><h3>${id?'Editar':'Nova'} OS</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form3"><div class="field"><label>Cliente *</label><select id="o_cli" onchange="bikesDoClienteSelect('o_cli','')"><option value="">Selecione...</option>${cli}</select></div><div class="field"><label>Bicicleta cadastrada</label><select id="o_bike_sel" onchange="let b=st.bikes.find(x=>x.id==this.value); if(b){$('o_bike').value=[b.marca,b.modelo,b.cor].filter(Boolean).join(' ')}"><option value="">Digitar manualmente</option></select></div><div class="field"><label>Funcionário responsável</label><select id="o_func"><option value="">Selecione quem fez o serviço...</option>${funcs}</select></div><div class="field"><label>Data</label><input id="o_data" type="date" value="${o.data||today()}"></div><div class="field"><label>Bike/equipamento *</label><input id="o_bike" value="${o.bike||''}"></div><div class="field"><label>Status</label><select id="o_status"><option>Aberta</option><option>Aguardando aprovação</option><option>Em execução</option><option>Pronta para retirada</option><option>Faturada</option><option>Cancelada</option></select></div><div class="field"><label>Desconto</label><input id="o_desc" type="number" step="0.01" value="${o.desc||0}"></div><div class="field"><label>Entrega prevista</label><input id="o_entrega" type="date" value="${o.entregaPrevista||''}"></div><div class="field"><label>Assinatura digital / aceite</label><input id="o_ass" value="${o.assinatura||''}" placeholder="Nome de quem autorizou/retirou"></div></div><div class="field"><label>Defeito relatado</label><input id="o_def" value="${o.defeito||''}"></div><div class="card"><h3>Peças usadas na OS</h3>${pecasHTML(o.pecas||[])}</div><div class="card"><h3>Mão de obra</h3>${maoHTML(o.mao||[])}</div><div class="grid2"><div class="card"><h3>Fotos antes</h3><input type="file" accept="image/*" multiple onchange="readImages(this,'fotosAntesBox')"><div id="fotosAntesBox" class="photos" data-photos='${JSON.stringify(o.fotosAntes||[])}'>${(o.fotosAntes||[]).map(src=>`<img class="thumb" src="${src}">`).join('')}</div></div><div class="card"><h3>Fotos depois</h3><input type="file" accept="image/*" multiple onchange="readImages(this,'fotosDepoisBox')"><div id="fotosDepoisBox" class="photos" data-photos='${JSON.stringify(o.fotosDepois||[])}'>${(o.fotosDepois||[]).map(src=>`<img class="thumb" src="${src}">`).join('')}</div></div></div><div class="field"><label>Observações</label><textarea id="o_obs">${o.obs||''}</textarea></div><div class="notice">A baixa no estoque será feita quando salvar a OS como <b>Pronta para retirada</b>. A garantia é calculada quando a OS for faturada.</div><div class="actions"><button class="btn goldbtn" onclick="saveOS('${id||''}')">Salvar OS</button></div>`);$('o_status').value=o.status||'Aberta';bikesDoClienteSelect('o_cli',o.bikeId||'')}
function saveOS(id){let old=st.os.find(x=>x.id==id),func=st.funcionarios.find(f=>f.id==$('o_func').value),bikeId=$('o_bike_sel').value;let obj={id:id||uid(),num:old?old.num:st.seqOS++,data:$('o_data').value,cliente:$('o_cli').value,bike:$('o_bike').value,bikeId,defeito:$('o_def').value,funcionarioId:$('o_func').value,funcionario:func?func.nome:'',status:$('o_status').value,desc:n($('o_desc').value),pecas:collectPecas(),mao:collectMao(),obs:$('o_obs').value,entregaPrevista:$('o_entrega').value,assinatura:$('o_ass').value,fotosAntes:JSON.parse($('fotosAntesBox').dataset.photos||'[]'),fotosDepois:JSON.parse($('fotosDepoisBox').dataset.photos||'[]'),baixouEstoque:old?!!old.baixouEstoque:false,garantiaAte:old?old.garantiaAte:''};if(!obj.cliente||!obj.bike)return alert('Informe cliente e bike.');if(obj.status=='Pronta para retirada'&&!obj.baixouEstoque){for(let p of obj.pecas){let e=st.estoque.find(x=>x.id==p.prodId);if(e){if(n(e.qtd)<n(p.qtd))return alert('Estoque insuficiente para: '+e.desc);e.qtd-=n(p.qtd)}}obj.baixouEstoque=true}upsert('os',obj);logAudit(id?'OS editada':'OS criada','OS #'+obj.num+' - '+obj.cliente);closeM();save()}
function receberOS(id){let o=st.os.find(x=>x.id==id),total=n($('pay_total').value),forma=$('pay_forma').value,obs=$('pay_obs').value,mix=null,entrada=total,status='Recebida';if(forma=='Misto'){mix={pix:n($('mix_pix').value),dinheiro:n($('mix_din').value),cartao:n($('mix_card').value)};if(Math.abs((mix.pix+mix.dinheiro+mix.cartao)-total)>0.01)return alert('A soma do pagamento misto precisa fechar com o total.')}if(['A prazo','Parcial','Crédito Parcelado'].includes(forma)){entrada=n($('pay_entrada').value);status=entrada>0?'Parcial / a receber':'A receber'}let v={id:uid(),num:st.seqVenda++,data:today(),cliente:o.cliente,origem:'OS #'+o.num,osId:o.id,funcionario:o.funcionario,funcionarioId:o.funcionarioId,total,forma,obs,mix,status,entrada,itens:[...(o.pecas||[]),...(o.mao||[]).map(m=>({nome:m.desc,qtd:1,preco:m.valor}))]};st.vendas.push(v);o.status=entrada>=total?'Faturada':'Pronta para retirada';if(o.status=='Faturada')o.garantiaAte=addDays(today(),n(st.config.garantiaDias||90));o.pagamento={forma,total,obs,mix,data:today(),vendaId:v.id,status};if(entrada>0)addCaixa('Entrada',entrada,'Entrada recebida '+v.origem+' — '+o.cliente,'OS / Serviço');if(entrada<total)gerarContasReceber(v,total,entrada,$('pay_parcelas')?.value,$('pay_venc')?.value);logAudit('OS recebida/faturada','OS #'+o.num+' - '+money(entrada));closeM();save()}
function agendaPage(){let rows=(st.agenda||[]).sort((a,b)=>(a.data+a.hora).localeCompare(b.data+b.hora)).map(a=>`<tr><td>${br(a.data)} ${a.hora||''}</td><td>${a.tipo}</td><td>${a.cliente||'—'}</td><td>${a.desc}</td><td>${a.status||'Agendado'}</td><td><button class="btn sm" onclick="openAgenda('${a.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('agenda','${a.id}')">Excluir</button></td></tr>`).join('');$('p-agenda').innerHTML=`<div class="card"><div class="head"><h3>Agenda da oficina</h3><button class="btn goldbtn" onclick="openAgenda()">+ Agendar</button></div><table class="table"><thead><tr><th>Data/Hora</th><th>Tipo</th><th>Cliente</th><th>Descrição</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="6" class="empty">Nada agendado.</td></tr>'}</tbody></table></div>`}
function openAgenda(id){let a=(st.agenda||[]).find(x=>x.id==id)||{data:today(),hora:'09:00',tipo:'Serviço',status:'Agendado'};let cli=st.clientes.map(c=>`<option ${a.cliente==c.nome?'selected':''}>${c.nome}</option>`).join('');modal(`<div class="mhead"><h3>Agenda</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form3"><div class="field"><label>Data</label><input id="ag_data" type="date" value="${a.data}"></div><div class="field"><label>Hora</label><input id="ag_hora" type="time" value="${a.hora||'09:00'}"></div><div class="field"><label>Tipo</label><select id="ag_tipo"><option>Serviço</option><option>Entrega prevista</option><option>Retirada</option><option>Retorno/Garantia</option></select></div><div class="field"><label>Cliente</label><select id="ag_cliente"><option value="">Selecione...</option>${cli}</select></div><div class="field"><label>Status</label><select id="ag_status"><option>Agendado</option><option>Concluído</option><option>Cancelado</option></select></div></div><div class="field"><label>Descrição</label><input id="ag_desc" value="${a.desc||''}"></div><div class="actions"><button class="btn goldbtn" onclick="saveAgenda('${id||''}')">Salvar</button></div>`);$('ag_tipo').value=a.tipo||'Serviço';$('ag_status').value=a.status||'Agendado'}
function saveAgenda(id){let obj={id:id||uid(),data:$('ag_data').value,hora:$('ag_hora').value,tipo:$('ag_tipo').value,cliente:$('ag_cliente').value,status:$('ag_status').value,desc:$('ag_desc').value};upsert('agenda',obj);logAudit(id?'Agenda editada':'Agenda criada',obj.desc);closeM();save()}
function crmPage(){let dias=n(st.config.revisaoDias||120);let rows=st.clientes.map(c=>{let oss=st.os.filter(o=>o.cliente==c.nome&&o.status=='Faturada').sort((a,b)=>(b.data||'').localeCompare(a.data||''));let last=oss[0];let diff=last?Math.floor((new Date(today()+'T00:00:00')-new Date((last.data||today())+'T00:00:00'))/86400000):9999;return {c,last,diff}}).filter(x=>x.diff>=dias).map(x=>`<tr><td><b>${x.c.nome}</b></td><td>${x.c.whats||'—'}</td><td>${x.last?br(x.last.data):'Nunca'}</td><td>${x.diff==9999?'Sem histórico':x.diff+' dias'}</td><td><button class="btn sm" onclick="enviarRevisaoWhats('${x.c.id}')">WhatsApp revisão</button></td></tr>`).join('');$('p-crm').innerHTML=`<div class="card"><div class="head"><h3>CRM de revisões</h3><button class="btn" onclick="go('config')">Configurar dias</button></div><div class="notice">Clientes com última revisão acima de ${dias} dias ou sem histórico.</div><table class="table"><thead><tr><th>Cliente</th><th>WhatsApp</th><th>Última OS</th><th>Tempo</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="5" class="empty">Nenhum cliente pendente de contato.</td></tr>'}</tbody></table></div>`}
function enviarRevisaoWhats(cid){let c=st.clientes.find(x=>x.id==cid);let msg=`Olá, ${c.nome}! Aqui é da May Bike. Já faz um tempo desde a última revisão da sua bike. Quer agendar uma revisão preventiva? 🚲`;window.open(whatsappUrl(msg,c.whats),'_blank')}
function auditoriaPage(){let rows=(st.audit||[]).map(a=>`<tr><td>${new Date(a.data).toLocaleString('pt-BR')}</td><td>${a.usuario}</td><td>${a.acao}</td><td>${a.detalhe}</td></tr>`).join('');$('p-auditoria').innerHTML=`<div class="card"><div class="head"><h3>Auditoria de usuários</h3><button class="btn" onclick="csvDownload('auditoria_maybike.csv', [['Data','Usuário','Ação','Detalhe'],...(st.audit||[]).map(a=>[new Date(a.data).toLocaleString('pt-BR'),a.usuario,a.acao,a.detalhe])])">Exportar CSV</button></div><table class="table"><thead><tr><th>Data</th><th>Usuário</th><th>Ação</th><th>Detalhe</th></tr></thead><tbody>${rows||'<tr><td colspan="4" class="empty">Sem registros.</td></tr>'}</tbody></table></div>`}
function config(){$('p-config').innerHTML=`<div class="card"><h3>Configurações V13 Enterprise</h3><div class="notice"><b>V13</b> mantém o mesmo Firebase <b>maybike-d8a6d</b> e preserva os dados existentes. Novidades: IPI, custo real, margem por categoria, bicicletas por cliente, fotos na OS, assinatura/aceite, agenda, garantia automática, CRM de revisões, metas e auditoria.</div><div class="toolbar" style="margin-top:14px"><button class="btn goldbtn" onclick="exportData()">Exportar backup JSON</button><label class="btn">Importar backup<input type="file" style="display:none" onchange="importData(this)"></label><button class="btn" onclick="regrasFirebase()">Ver regras Firebase</button></div><hr style="border-color:var(--line)"><h3>Precificação e estoque</h3><div class="form3"><div class="field"><label>Margem padrão de peças (%)</label><input id="cfg_margem" type="number" step="0.01" value="${st.config.margemPadrao}"></div><div class="field"><label>Margem mínima alerta (%)</label><input id="cfg_minima" type="number" step="0.01" value="${st.config.margemMinima}"></div><div class="field"><label>Meta mensal de faturamento</label><input id="cfg_meta" type="number" step="0.01" value="${st.config.metaMensal||0}"></div></div><h3>Margem por categoria</h3><div id="catBox">${(st.categoriasMargem||[]).map((c,i)=>`<div class="lineitem" style="grid-template-columns:2fr 1fr auto"><input class="cat_nome" value="${c.cat}"><input class="cat_margem" type="number" step="0.01" value="${c.margem}"><button class="btn redbtn sm" onclick="this.parentElement.remove()">X</button></div>`).join('')}</div><button class="btn sm" onclick="$('catBox').insertAdjacentHTML('beforeend','<div class=&quot;lineitem&quot; style=&quot;grid-template-columns:2fr 1fr auto&quot;><input class=&quot;cat_nome&quot; placeholder=&quot;Categoria&quot;><input class=&quot;cat_margem&quot; type=&quot;number&quot; step=&quot;0.01&quot; value=&quot;75&quot;><button class=&quot;btn redbtn sm&quot; onclick=&quot;this.parentElement.remove()&quot;>X</button></div>')">+ Categoria</button><hr style="border-color:var(--line)"><h3>Financeiro, garantia e CRM</h3><div class="form3"><div class="field"><label>Multa por atraso (%)</label><input id="cfg_multa" type="number" step="0.01" value="${st.config.multaPercent}"></div><div class="field"><label>Juros ao mês (%)</label><input id="cfg_juros" type="number" step="0.01" value="${st.config.jurosMesPercent}"></div><div class="field"><label>Comissão mecânico (%)</label><input id="cfg_commec" type="number" step="0.01" value="${st.config.comissaoMecanicoPercent}"></div><div class="field"><label>Garantia padrão OS (dias)</label><input id="cfg_garantia" type="number" value="${st.config.garantiaDias}"></div><div class="field"><label>Revisão periódica após (dias)</label><input id="cfg_revisao" type="number" value="${st.config.revisaoDias}"></div></div><div class="actions"><button class="btn goldbtn" onclick="saveConfigV13()">Salvar configurações</button></div><hr style="border-color:var(--line)"><h3>Usuários e permissões</h3><div class="form3"><input id="u_nome" placeholder="Nome do usuário"><input id="u_login" placeholder="Login"><select id="u_perfil"><option>Administrador</option><option>Mecânico</option><option>Vendedor</option><option>Financeiro</option></select></div><div class="form2"><input id="u_senha" placeholder="Senha"><button class="btn goldbtn" onclick="addUserSecure()">Adicionar usuário</button></div><table class="table"><thead><tr><th>Nome</th><th>Login</th><th>Perfil</th><th></th></tr></thead><tbody>${st.users.map((u,i)=>`<tr><td>${u.nome||u.u}</td><td>${u.u}</td><td>${u.perfil||'Administrador'}</td><td>${i>0?`<button class="btn redbtn sm" onclick="st.users.splice(${i},1);save();config()">Excluir</button>`:'Principal'}</td></tr>`).join('')}</tbody></table></div>`}
function saveConfigV13(){st.config.margemPadrao=n($('cfg_margem').value);st.config.margemMinima=n($('cfg_minima').value);st.config.metaMensal=n($('cfg_meta').value);st.config.multaPercent=n($('cfg_multa').value);st.config.jurosMesPercent=n($('cfg_juros').value);st.config.comissaoMecanicoPercent=n($('cfg_commec').value);st.config.garantiaDias=n($('cfg_garantia').value);st.config.revisaoDias=n($('cfg_revisao').value);st.categoriasMargem=[...document.querySelectorAll('#catBox .lineitem')].map(r=>({cat:r.querySelector('.cat_nome').value,margem:n(r.querySelector('.cat_margem').value)})).filter(x=>x.cat);logAudit('Configurações alteradas','V13');save()}
function printOS(id){let o=st.os.find(x=>x.id==id),t=calcOS(o);let cliente=st.clientes.find(c=>c.nome==o.cliente)||{};$('print').innerHTML=`<div style="text-align:center;border-bottom:2px solid #111;padding-bottom:12px"><h1>🚲 May Bike</h1><p>WhatsApp: 42 98842-5435 | E-mail: maybikee@gmail.com</p><h2>ORDEM DE SERVIÇO #${o.num}</h2></div><p><b>Cliente:</b> ${o.cliente} &nbsp; <b>CPF:</b> ${cliente.cpf||'—'}</p><p><b>Endereço:</b> ${cliente.end||'—'} ${cliente.cidade||''}</p><p><b>Funcionário:</b> ${o.funcionario||'—'} &nbsp; <b>Status:</b> ${o.status}</p><p><b>Bike:</b> ${o.bike}</p><p><b>Defeito relatado:</b> ${o.defeito||'—'}</p><table><tr><th>Item</th><th>Qtd</th><th>Valor</th></tr>${(o.pecas||[]).map(p=>`<tr><td>${p.nome}</td><td>${p.qtd}</td><td>${money(p.qtd*p.preco)}</td></tr>`).join('')}${(o.mao||[]).map(m=>`<tr><td>${m.desc}</td><td>1</td><td>${money(m.valor)}</td></tr>`).join('')}<tr><td colspan="2"><b>Desconto</b></td><td>${money(o.desc||0)}</td></tr></table><h2>Total: ${money(t.total)}</h2><p><b>Garantia:</b> ${st.config.garantiaDias||90} dias para mão de obra. ${o.garantiaAte?'Válida até '+br(o.garantiaAte):''}</p><p><b>Assinatura/Aceite:</b> ${o.assinatura||'____________________________'}</p>${(o.fotosAntes||[]).length?'<p><b>Fotos antes registradas:</b> '+o.fotosAntes.length+'</p>':''}${(o.fotosDepois||[]).length?'<p><b>Fotos depois registradas:</b> '+o.fotosDepois.length+'</p>':''}<br><p>Assinatura cliente: ________________________________</p><p>Assinatura loja: ___________________________________</p>`;window.print()}



// ===== MAY BIKE V15 — CAIXA DIÁRIO, CONCILIAÇÃO, TAXAS, INVENTÁRIO E DRE =====
(function(){
  const oldMigrate = migrateV13;
  migrateV13 = function(){
    oldMigrate();
    st.caixasDiarios = st.caixasDiarios || [];
    st.inventarios = st.inventarios || [];
    st.config = {
      taxaDebitoPercent: 1.99,
      taxaCreditoPercent: 3.49,
      taxaCreditoParceladoPercent: 4.99,
      taxaPixPercent: 0,
      ...st.config
    };
    (st.vendas||[]).forEach(v=>{ if(!v.data) v.data=today(); if(!v.forma) v.forma='Dinheiro'; });
    (st.caixa||[]).forEach(c=>{ if(!c.forma) c.forma = formaPorCategoria(c); });
  };

  const oldRender = render;
  render = function(p){
    if(p==='fechamento') return fechamentoPage();
    if(p==='inventario') return inventarioPage();
    if(p==='dre') return drePage();
    return oldRender(p);
  };

  try{
    const i=pages.findIndex(p=>p[0]==='caixa');
    if(i>=0 && !pages.some(p=>p[0]==='fechamento')) pages.splice(i+1,0,['fechamento','🧮 Fechamento'],['inventario','📋 Inventário'],['dre','📊 DRE / Lucro']);
  }catch(e){}
})();

function formaPorCategoria(c){
  let t=((c.forma||'')+' '+(c.cat||'')+' '+(c.desc||'')).toLowerCase();
  if(t.includes('pix')) return 'PIX';
  if(t.includes('crédito')||t.includes('credito')) return 'Cartão crédito';
  if(t.includes('débito')||t.includes('debito')) return 'Cartão débito';
  if(t.includes('prazo')||t.includes('receber')) return 'A prazo';
  return 'Dinheiro';
}
function usuarioAtual(){try{let u=JSON.parse(sessionStorage.mbUser||'{}');return u.nome||u.u||'Admin'}catch(e){return 'Admin'}}
function caixaDoDia(data=today()){let c=st.caixasDiarios.find(x=>x.data===data);if(!c){c={id:uid(),data,abertura:0,responsavelAbertura:'',status:'Não aberto',sangrias:[],suprimentos:[],fechamento:null,obs:''};st.caixasDiarios.push(c)}return c}
function vendasDia(data=today()){return (st.vendas||[]).filter(v=>v.data===data)}
function lancDia(data=today()){return (st.caixa||[]).filter(c=>c.data===data)}
function normForma(f){f=String(f||'').toLowerCase(); if(f.includes('pix'))return 'PIX'; if(f.includes('débito')||f.includes('debito'))return 'Cartão débito'; if(f.includes('crédito')||f.includes('credito'))return 'Cartão crédito'; if(f.includes('prazo')||f.includes('receber'))return 'A prazo'; if(f.includes('misto'))return 'Misto'; return 'Dinheiro'}
function resumoPagamentosDia(data=today()){
  let r={'Dinheiro':0,'PIX':0,'Cartão débito':0,'Cartão crédito':0,'A prazo':0,'Misto':0};
  vendasDia(data).forEach(v=>{let f=normForma(v.forma); if(f==='Misto'&&v.mix){r.PIX+=n(v.mix.pix);r.Dinheiro+=n(v.mix.dinheiro);r['Cartão crédito']+=n(v.mix.cartao)}else r[f]=(r[f]||0)+n(v.entrada||v.total)});
  lancDia(data).forEach(c=>{ if(c.origem==='fechamento')return; let f=normForma(c.forma||c.cat); if(c.tipo==='Entrada' && !(String(c.cat||'').toLowerCase().includes('sangria'))) r[f]=(r[f]||0)+n(c.valor); });
  return r;
}
function despesasDinheiroDia(data=today()){return lancDia(data).filter(c=>c.tipo==='Saída'&&normForma(c.forma||c.cat)==='Dinheiro'&&!String(c.cat||'').toLowerCase().includes('sangria')).reduce((a,c)=>a+n(c.valor),0)}
function resumoCaixaDia(data=today()){
  let cx=caixaDoDia(data), p=resumoPagamentosDia(data);
  let supr=(cx.suprimentos||[]).reduce((a,b)=>a+n(b.valor),0), sang=(cx.sangrias||[]).reduce((a,b)=>a+n(b.valor),0), saidas=despesasDinheiroDia(data);
  let esperado=n(cx.abertura)+n(p['Dinheiro'])+supr-sang-saidas;
  return {cx,p,supr,sang,saidas,esperado};
}
function taxasCartaoPeriodo(inicio,fim){let deb=0,cred=0,credParc=0,pix=0; (st.vendas||[]).forEach(v=>{let d=v.data||''; if(d<inicio||d>fim)return; let f=normForma(v.forma); if(f==='Cartão débito')deb+=n(v.total); else if(f==='Cartão crédito'){ if(String(v.forma||'').toLowerCase().includes('parcel'))credParc+=n(v.total); else cred+=n(v.total)} else if(f==='PIX')pix+=n(v.total);});return {deb,cred,credParc,pix,total:deb*n(st.config.taxaDebitoPercent)/100+cred*n(st.config.taxaCreditoPercent)/100+credParc*n(st.config.taxaCreditoParceladoPercent)/100+pix*n(st.config.taxaPixPercent)/100}}
function caixa(){
  let data=$('cx_data')?.value||today(), r=resumoCaixaDia(data), p=r.p, f=r.cx.fechamento||{}, diff=f.contado!==undefined?n(f.contado)-r.esperado:0;
  let rows=lancDia(data).slice().reverse().map(x=>`<tr><td>${x.hora||''}</td><td>${x.tipo}</td><td>${x.forma||formaPorCategoria(x)}</td><td>${x.cat||''}</td><td>${x.desc||''}</td><td class="${x.tipo==='Entrada'?'green':'red'}"><b>${money(x.valor)}</b></td></tr>`).join('');
  $('p-caixa').innerHTML=`<div class="card"><div class="head"><h3>Caixa diário</h3><div class="toolbar"><input id="cx_data" type="date" value="${data}" onchange="caixa()"><button class="btn goldbtn" onclick="openAberturaCaixa('${data}')">Abrir / Reforço</button><button class="btn" onclick="openCx()">+ Lançamento</button><button class="btn" onclick="go('fechamento')">Fechar caixa</button></div></div><div class="grid4"><div class="metric"><div class="label">Saldo inicial / reforço</div><div class="value gold">${money(r.cx.abertura)}</div></div><div class="metric"><div class="label">Dinheiro recebido</div><div class="value green">${money(p['Dinheiro'])}</div></div><div class="metric"><div class="label">Sangrias</div><div class="value red">${money(r.sang)}</div></div><div class="metric"><div class="label">Dinheiro esperado</div><div class="value blue">${money(r.esperado)}</div></div></div><div class="grid4"><div class="metric"><div class="label">PIX</div><div class="value green">${money(p.PIX)}</div></div><div class="metric"><div class="label">Cartão débito</div><div class="value green">${money(p['Cartão débito'])}</div></div><div class="metric"><div class="label">Cartão crédito</div><div class="value green">${money(p['Cartão crédito'])}</div></div><div class="metric"><div class="label">A prazo</div><div class="value gold">${money(p['A prazo'])}</div></div></div>${f.contado!==undefined?`<div class="notice"><b>Caixa fechado:</b> contado ${money(f.contado)} | diferença <b class="${diff>=0?'green':'red'}">${money(diff)}</b> | responsável: ${f.responsavel||'—'}</div>`:''}</div><div class="card"><h3>Movimentos do dia</h3><table class="table"><thead><tr><th>Hora</th><th>Tipo</th><th>Forma</th><th>Categoria</th><th>Descrição</th><th>Valor</th></tr></thead><tbody>${rows||'<tr><td colspan="6" class="empty">Nenhum movimento.</td></tr>'}</tbody></table></div>`;
}
function openAberturaCaixa(data=today()){let c=caixaDoDia(data);modal(`<div class="mhead"><h3>Abertura / reforço de caixa</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Data</label><input id="ab_data" type="date" value="${data}"></div><div class="field"><label>Saldo inicial em dinheiro</label><input id="ab_valor" type="number" step="0.01" value="${c.abertura||0}"></div><div class="field"><label>Responsável</label><input id="ab_resp" value="${c.responsavelAbertura||usuarioAtual()}"></div><div class="field"><label>Observação</label><input id="ab_obs" value="${c.obs||''}"></div></div><div class="actions"><button class="btn goldbtn" onclick="salvarAberturaCaixa()">Salvar abertura</button></div>`)}
function salvarAberturaCaixa(){let data=$('ab_data').value||today(), c=caixaDoDia(data);c.abertura=n($('ab_valor').value);c.responsavelAbertura=$('ab_resp').value;c.obs=$('ab_obs').value;c.status='Aberto';logAudit('Abertura/reforço de caixa',`${data} - ${money(c.abertura)}`);closeM();save()}
function openCx(){modal(`<div class="mhead"><h3>Novo movimento de caixa</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form3"><div class="field"><label>Tipo</label><select id="cx_tipo"><option>Entrada</option><option>Saída</option><option>Sangria</option><option>Suprimento</option></select></div><div class="field"><label>Forma</label><select id="cx_forma"><option>Dinheiro</option><option>PIX</option><option>Cartão débito</option><option>Cartão crédito</option><option>A prazo</option></select></div><div class="field"><label>Valor</label><input id="cx_valor" type="number" step="0.01"></div><div class="field"><label>Categoria</label><input id="cx_cat" value="Outro"></div><div class="field"><label>Descrição</label><input id="cx_desc"></div><div class="field"><label>Data</label><input id="cx_data_mov" type="date" value="${today()}"></div></div><div class="actions"><button class="btn goldbtn" onclick="salvarMovCaixa()">Salvar</button></div>`)}
function salvarMovCaixa(){let tipo=$('cx_tipo').value, valor=n($('cx_valor').value), data=$('cx_data_mov').value||today(), forma=$('cx_forma').value, cat=$('cx_cat').value, desc=$('cx_desc').value;if(!valor)return alert('Informe o valor.');let c=caixaDoDia(data);if(tipo==='Sangria'){c.sangrias.push({id:uid(),valor,desc,forma:'Dinheiro',hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})});st.caixa.push({id:uid(),tipo:'Saída',valor,desc:desc||'Sangria de caixa',cat:'Sangria',forma:'Dinheiro',data,hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})})}else if(tipo==='Suprimento'){c.suprimentos.push({id:uid(),valor,desc,forma:'Dinheiro',hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})});st.caixa.push({id:uid(),tipo:'Entrada',valor,desc:desc||'Suprimento de caixa',cat:'Suprimento',forma:'Dinheiro',data,hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})})}else st.caixa.push({id:uid(),tipo,valor,desc,cat,forma,data,hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})});logAudit('Movimento de caixa',`${tipo} ${money(valor)} - ${desc}`);closeM();save()}
function fechamentoPage(){let data=$('fec_data')?.value||today(), r=resumoCaixaDia(data), p=r.p, tx=taxasCartaoPeriodo(data,data), f=r.cx.fechamento||{};let diff=f.contado!==undefined?n(f.contado)-r.esperado:0;$('p-fechamento').innerHTML=`<div class="card"><div class="head"><h3>Fechamento diário de caixa</h3><div class="toolbar"><input id="fec_data" type="date" value="${data}" onchange="fechamentoPage()"><button class="btn" onclick="printFechamento('${data}')">Imprimir/PDF</button></div></div><div class="grid4"><div class="metric"><div class="label">Dinheiro esperado</div><div class="value blue">${money(r.esperado)}</div></div><div class="metric"><div class="label">PIX sistema</div><div class="value green">${money(p.PIX)}</div></div><div class="metric"><div class="label">Cartões sistema</div><div class="value green">${money(p['Cartão débito']+p['Cartão crédito'])}</div></div><div class="metric"><div class="label">Taxas estimadas</div><div class="value red">${money(tx.total)}</div></div></div><div class="form3"><div class="field"><label>Dinheiro contado no caixa</label><input id="fec_contado" type="number" step="0.01" value="${f.contado??''}"></div><div class="field"><label>PIX conferido no banco</label><input id="fec_pix" type="number" step="0.01" value="${f.pixConferido??p.PIX}"></div><div class="field"><label>Cartão débito conferido</label><input id="fec_deb" type="number" step="0.01" value="${f.debitoConferido??p['Cartão débito']}"></div><div class="field"><label>Cartão crédito conferido</label><input id="fec_cred" type="number" step="0.01" value="${f.creditoConferido??p['Cartão crédito']}"></div><div class="field"><label>Responsável</label><input id="fec_resp" value="${f.responsavel||usuarioAtual()}"></div><div class="field"><label>Observações</label><input id="fec_obs" value="${f.obs||''}"></div></div><div class="notice">Diferenças são calculadas entre sistema x conferência física/banco. Para dinheiro: abertura + vendas dinheiro + suprimentos - sangrias - saídas em dinheiro.</div><div class="actions"><button class="btn goldbtn" onclick="salvarFechamento('${data}')">Fechar caixa do dia</button></div></div><div class="card"><h3>Resumo do dia</h3><table class="table"><tbody><tr><td>Saldo inicial</td><td>${money(r.cx.abertura)}</td></tr><tr><td>Dinheiro recebido</td><td>${money(p.Dinheiro)}</td></tr><tr><td>Suprimentos</td><td>${money(r.supr)}</td></tr><tr><td>Sangrias</td><td>${money(r.sang)}</td></tr><tr><td>Saídas em dinheiro</td><td>${money(r.saidas)}</td></tr><tr><td><b>Dinheiro esperado</b></td><td><b>${money(r.esperado)}</b></td></tr>${f.contado!==undefined?`<tr><td><b>Diferença final</b></td><td><b class="${diff>=0?'green':'red'}">${money(diff)}</b></td></tr>`:''}</tbody></table></div>`}
function salvarFechamento(data){let r=resumoCaixaDia(data), c=r.cx;c.fechamento={dataHora:new Date().toISOString(),contado:n($('fec_contado').value),pixConferido:n($('fec_pix').value),debitoConferido:n($('fec_deb').value),creditoConferido:n($('fec_cred').value),responsavel:$('fec_resp').value,obs:$('fec_obs').value,dinheiroEsperado:r.esperado};c.status='Fechado';logAudit('Fechamento de caixa',`${data} diferença ${money(c.fechamento.contado-r.esperado)}`);save()}
function printFechamento(data){let r=resumoCaixaDia(data), p=r.p, f=r.cx.fechamento||{}, diff=(f.contado!==undefined?n(f.contado)-r.esperado:0);let html=`<h1>May Bike — Fechamento de Caixa</h1><p>Data: ${br(data)}</p><p>Responsável: ${f.responsavel||r.cx.responsavelAbertura||'—'}</p><table><tr><td>Saldo inicial</td><td>${money(r.cx.abertura)}</td></tr><tr><td>Dinheiro recebido</td><td>${money(p.Dinheiro)}</td></tr><tr><td>PIX</td><td>${money(p.PIX)}</td></tr><tr><td>Cartão débito</td><td>${money(p['Cartão débito'])}</td></tr><tr><td>Cartão crédito</td><td>${money(p['Cartão crédito'])}</td></tr><tr><td>Sangrias</td><td>${money(r.sang)}</td></tr><tr><td>Dinheiro esperado</td><td>${money(r.esperado)}</td></tr><tr><td>Dinheiro contado</td><td>${money(f.contado||0)}</td></tr><tr><td>Diferença</td><td>${money(diff)}</td></tr></table><p>Observações: ${f.obs||''}</p>`;printHTML(html)}
function drePage(){let mes=$('dre_mes')?.value||monthKey(today()), inicio=mes+'-01', fim=mes+'-31';let vendas=(st.vendas||[]).filter(v=>monthKey(v.data)===mes);let receita=vendas.reduce((a,v)=>a+n(v.total),0);let custos=vendas.reduce((a,v)=>a+(v.itens||[]).reduce((s,i)=>{let e=st.estoque.find(x=>x.id==i.prodId);return s+n(i.qtd)*(e?n(e.custoReal||e.custo):0)},0),0);let taxas=taxasCartaoPeriodo(inicio,fim).total;let despesas=(st.contas||[]).filter(c=>c.tipo==='A Pagar'&&monthKey(c.venc)===mes&&(c.status==='Pago'||c.status==='Aberto')).reduce((a,c)=>a+n(c.valorOriginal||c.valor),0);let lucro=receita-custos-taxas-despesas;$('p-dre').innerHTML=`<div class="card"><div class="head"><h3>DRE simplificado</h3><div class="toolbar"><input id="dre_mes" type="month" value="${mes}" onchange="drePage()"><button class="btn" onclick="exportDRE('${mes}')">Exportar CSV</button></div></div><div class="grid4"><div class="metric"><div class="label">Receita bruta</div><div class="value green">${money(receita)}</div></div><div class="metric"><div class="label">Custos produtos</div><div class="value red">${money(custos)}</div></div><div class="metric"><div class="label">Taxas cartão/PIX</div><div class="value red">${money(taxas)}</div></div><div class="metric"><div class="label">Lucro líquido estimado</div><div class="value ${lucro>=0?'green':'red'}">${money(lucro)}</div></div></div><table class="table"><tbody><tr><td>Receita de vendas/OS</td><td>${money(receita)}</td></tr><tr><td>(-) Custo das mercadorias/peças</td><td>${money(custos)}</td></tr><tr><td>(-) Taxas de cartão/PIX</td><td>${money(taxas)}</td></tr><tr><td>(-) Despesas/contas do mês</td><td>${money(despesas)}</td></tr><tr><td><b>Resultado estimado</b></td><td><b class="${lucro>=0?'green':'red'}">${money(lucro)}</b></td></tr></tbody></table></div>`}
function exportDRE(mes){let inicio=mes+'-01',fim=mes+'-31',v=(st.vendas||[]).filter(x=>monthKey(x.data)===mes),receita=v.reduce((a,b)=>a+n(b.total),0),taxas=taxasCartaoPeriodo(inicio,fim).total;csvDownload('dre_'+mes+'.csv',[['Mês',mes],['Receita',receita],['Taxas',taxas]])}
function inventarioPage(){let rows=(st.estoque||[]).map(e=>`<tr><td>${e.cod||''}</td><td>${e.desc}</td><td>${e.qtd}</td><td><input class="inv_qtd" data-id="${e.id}" type="number" value="${e.qtd}" style="width:90px"></td><td>${money(n(e.qtd)*n(e.custoReal||e.custo))}</td></tr>`).join('');$('p-inventario').innerHTML=`<div class="card"><div class="head"><h3>Inventário de estoque</h3><button class="btn goldbtn" onclick="salvarInventario()">Salvar contagem e ajustar estoque</button></div><div class="notice">Use para contagem física. O sistema registra a diferença e ajusta o estoque.</div><table class="table"><thead><tr><th>Código</th><th>Produto</th><th>Sistema</th><th>Contado</th><th>Capital atual</th></tr></thead><tbody>${rows||'<tr><td colspan="5" class="empty">Sem produtos.</td></tr>'}</tbody></table></div><div class="card"><h3>Histórico de inventários</h3><table class="table"><thead><tr><th>Data</th><th>Responsável</th><th>Itens com diferença</th><th>Observação</th></tr></thead><tbody>${(st.inventarios||[]).slice().reverse().map(i=>`<tr><td>${br(i.data)}</td><td>${i.responsavel}</td><td>${i.diffs.length}</td><td>${i.obs||''}</td></tr>`).join('')||'<tr><td colspan="4" class="empty">Nenhum inventário salvo.</td></tr>'}</tbody></table></div>`}
function salvarInventario(){let diffs=[];document.querySelectorAll('.inv_qtd').forEach(inp=>{let e=st.estoque.find(x=>x.id==inp.dataset.id),cont=n(inp.value);if(e&&cont!==n(e.qtd)){diffs.push({prodId:e.id,cod:e.cod,desc:e.desc,sistema:n(e.qtd),contado:cont,diferenca:cont-n(e.qtd)});e.qtd=cont}});st.inventarios.push({id:uid(),data:today(),responsavel:usuarioAtual(),diffs,obs:'Inventário manual'});logAudit('Inventário salvo',`${diffs.length} itens com diferença`);save()}
function printHTML(html){let w=window.open('','_blank');w.document.write(`<html><head><title>May Bike</title><style>body{font-family:Arial;padding:30px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ddd;padding:8px}</style></head><body>${html}</body></html>`);w.document.close();w.print()}
function exportRelatoriosCSV(){let rows=[['Tipo','Valor'],['Vendas',st.vendas.length],['OS',st.os.length],['Caixa',st.caixa.length],['Contas',st.contas.length]];csvDownload('relatorios_maybike.csv',rows)}
function exportContasCSV(){let rows=[['Código','Vencimento','Tipo','Cliente','Descrição','Valor','Status'],...(st.contas||[]).map(c=>[c.cod,c.venc,c.tipo,c.cliente,c.desc,totalConta(c),c.status])];csvDownload('contas_maybike.csv',rows)}


