function ensureSaasPages(){
  if(!pages.find(p=>p[0]=='loja')) pages.push(['loja','🏢 Minha Loja']);
  if(!pages.find(p=>p[0]=='master')) pages.push(['master','👑 Painel Master']);
  const content=document.querySelector('.content');
  ['loja','master'].forEach(p=>{ if(!$('p-'+p) && content){ const d=document.createElement('div'); d.id='p-'+p; d.className='page'; content.appendChild(d);} });
}
function setLoginSaasUI(){
  const loginBox=document.querySelector('#login .box'); if(!loginBox) return;
  document.title='My PDV — SaaS V1.0.3 Comercial';
  const h=loginBox.querySelector('h1'); if(h) h.textContent='My PDV';
  const p=loginBox.querySelector('.brand p'); if(p) p.textContent='SaaS V1.0.3 Comercial — Multiempresa';
  const user=$('user'); if(user){user.value=''; user.placeholder='seuemail@loja.com';}
  const pass=$('pass'); if(pass){pass.value=''; pass.placeholder='Senha';}
  const notice=loginBox.querySelector('.notice'); if(notice) notice.innerHTML='Entre com seu e-mail ou crie a primeira loja para começar.';
  if(!$('saasSignupBtn')) loginBox.insertAdjacentHTML('beforeend',`<div class="toolbar" style="margin-top:12px"><button id="saasSignupBtn" class="btn" style="width:100%" onclick="openSaasSignup()">Criar loja / teste grátis</button><button class="btn" style="width:100%" onclick="resetPassword()">Recuperar senha</button></div>`);
}
async function resetPassword(){let email=($('user')?.value||'').trim(); if(!email)return alert('Digite seu e-mail no campo usuário.'); try{await auth.sendPasswordResetEmail(email); alert('E-mail de recuperação enviado.')}catch(e){alert('Erro: '+(e.message||e))}}
function openSaasSignup(){
  modal(`<div class="mhead"><h3>Criar loja no My PDV</h3><button class="btn" onclick="closeM()">Fechar</button></div>
  <div class="notice">Crie a empresa e o primeiro usuário administrador. Cada loja terá dados separados na nuvem.</div>
  <div class="form2"><div class="field"><label>Nome da loja *</label><input id="sg_loja" placeholder="Ex: Oficina do João"></div><div class="field"><label>Segmento</label><select id="sg_segmento"><option>Bicicletaria/Oficina</option><option>Assistência técnica</option><option>Autopeças</option><option>Loja de celulares</option><option>Informática</option><option>Pequeno varejo</option></select></div><div class="field"><label>CNPJ/CPF</label><input id="sg_cnpj"></div><div class="field"><label>WhatsApp</label><input id="sg_whats"></div><div class="field"><label>E-mail da loja</label><input id="sg_email_loja"></div><div class="field"><label>Cidade/UF</label><input id="sg_cidade"></div><div class="field"><label>Seu nome *</label><input id="sg_nome"></div><div class="field"><label>Seu e-mail de login *</label><input id="sg_email"></div><div class="field"><label>Senha *</label><input id="sg_senha" type="password"></div><div class="field"><label>Plano</label><select id="sg_plano"><option>Starter</option><option>Pro</option><option>Premium</option></select></div></div>
  <div class="actions"><button class="btn goldbtn" onclick="createSaasCompany()">Criar empresa</button></div>`)
}
async function createSaasCompany(){
  const nomeLoja=$('sg_loja').value.trim(), nome=$('sg_nome').value.trim(), email=$('sg_email').value.trim(), senha=$('sg_senha').value;
  if(!nomeLoja||!nome||!email||!senha) return alert('Preencha loja, seu nome, e-mail e senha.');
  try{
    const cred=await auth.createUserWithEmailAndPassword(email,senha);
    const empresaId='emp_'+uid();
    const masterEmail='douglasomendes2510@gmail.com';
    const master=email.toLowerCase()==masterEmail;
    const empresa={id:empresaId,nome:nomeLoja,segmento:$('sg_segmento').value,cnpj:$('sg_cnpj').value,whats:$('sg_whats').value,email:$('sg_email_loja').value||email,cidade:$('sg_cidade').value,plano:$('sg_plano').value,status:'Ativa',criadaEm:new Date().toISOString(),vencimento:addDays(today(),15),ownerUid:cred.user.uid};
    await db.collection('empresas').doc(empresaId).set(empresa);
    await db.collection('usuarios').doc(cred.user.uid).set({uid:cred.user.uid,empresaId,nome,email,perfil:'Proprietário',master,ativo:true,criadoEm:new Date().toISOString()});
    st=makeEmptyState(); st.empresa=empresa; st.users=[{u:email,nome,perfil:'Proprietário'}]; currentEmpresaId=empresaId; currentUser=cred.user; currentProfile={empresaId,nome,email,perfil:'Proprietário',master}; isMaster=master; await save(); closeM();
  }catch(e){alert('Erro ao criar empresa: '+(e.message||e)+'\n\nSe aparecer auth/api-key-not-valid, confira se o app.js publicado é a V1.0.3 e se a API key do Firebase My PDV não está bloqueada por restrição no Google Cloud.')}
}
async function initSaasAuth(){
  setLoginSaasUI();
  if(!auth){alert('Firebase Auth não carregou. Confira os scripts do Firebase.'); return;}
  auth.onAuthStateChanged(async user=>{
    if(user){
      currentUser=user;
      try{
        let udoc=await db.collection('usuarios').doc(user.uid).get();
        if(!udoc.exists){ $('login').style.display='grid'; $('app').style.display='none'; alert('Usuário sem empresa vinculada. Crie uma loja ou peça acesso ao administrador.'); return; }
        currentProfile=udoc.data(); currentEmpresaId=currentProfile.empresaId; isMaster=!!currentProfile.master;
        await loadCloud(); gerarRecorrentes(); sessionStorage.mb='1'; sessionStorage.mbUser=JSON.stringify({u:user.email,nome:currentProfile.nome||user.email,perfil:currentProfile.perfil||'Usuário',empresaId:currentEmpresaId,master:isMaster});
        $('login').style.display='none'; $('app').style.display='block'; updateSaasBrand(); go('dashboard');
      }catch(e){console.warn(e); alert('Erro ao carregar usuário: '+(e.message||e));}
    }else{ currentEmpresaId=null; currentUser=null; currentProfile=null; isMaster=false; $('login').style.display='grid'; $('app').style.display='none'; render('dashboard'); }
  });
}
function updateSaasBrand(){
  const emp=st.empresa||{};
  document.title=(emp.nome||'My PDV')+' — My PDV SaaS V1.0.3';
  document.querySelectorAll('.store h1').forEach(x=>x.textContent=emp.nome||'My PDV');
  document.querySelectorAll('.store small').forEach(x=>x.innerHTML=`WhatsApp: <b>${emp.whats||'—'}</b><br>E-mail: <b>${emp.email||'—'}</b><br>Plano: <b>${emp.plano||'Starter'}</b><br>My PDV SaaS V1.0.3`);
}
function loja(){
 const e=st.empresa||{};
 $('p-loja').innerHTML=`<div class="grid3"><div class="metric"><div class="label">Plano</div><div class="value gold">${e.plano||'Starter'}</div></div><div class="metric"><div class="label">Status</div><div class="value green">${e.status||'Ativa'}</div></div><div class="metric"><div class="label">Vencimento</div><div class="value blue">${br(e.vencimento)||'—'}</div></div></div><div class="card"><h3>Dados da loja</h3><div class="form3"><div class="field"><label>Nome</label><input id="lj_nome" value="${e.nome||''}"></div><div class="field"><label>CNPJ/CPF</label><input id="lj_cnpj" value="${e.cnpj||''}"></div><div class="field"><label>Segmento</label><input id="lj_segmento" value="${e.segmento||''}"></div><div class="field"><label>WhatsApp</label><input id="lj_whats" value="${e.whats||''}"></div><div class="field"><label>E-mail</label><input id="lj_email" value="${e.email||''}"></div><div class="field"><label>Cidade/UF</label><input id="lj_cidade" value="${e.cidade||''}"></div></div><div class="field"><label>Logo da loja (base64 para PDFs e telas futuras)</label><input type="file" accept="image/*" onchange="loadCompanyLogo(this)"></div><div class="actions"><button class="btn goldbtn" onclick="saveLoja()">Salvar dados da loja</button><button class="btn" onclick="exportData()">Exportar backup JSON</button><label class="btn">Importar backup<input type="file" style="display:none" onchange="importData(this)"></label></div></div><div class="card"><h3>Usuários da empresa</h3><div class="notice">V1.0: o proprietário já está vinculado. Na próxima versão comercial entra convite de usuários por e-mail e permissões avançadas.</div></div>`;
}
function saveLoja(){st.empresa={...(st.empresa||{}),nome:$('lj_nome').value,cnpj:$('lj_cnpj').value,segmento:$('lj_segmento').value,whats:$('lj_whats').value,email:$('lj_email').value,cidade:$('lj_cidade').value}; db.collection('empresas').doc(currentEmpresaId).set(st.empresa,{merge:true}); updateSaasBrand(); save();}
function loadCompanyLogo(input){const f=input.files&&input.files[0]; if(!f)return; const r=new FileReader(); r.onload=()=>{st.empresa=st.empresa||{}; st.empresa.logo=r.result; save(); alert('Logo salva na empresa.');}; r.readAsDataURL(f);}
async function master(){
 if(!isMaster){$('p-master').innerHTML='<div class="card"><h3>Acesso restrito</h3><p>Somente o administrador Master do My PDV pode acessar este painel.</p></div>';return;}
 let snap=await db.collection('empresas').orderBy('criadaEm','desc').limit(100).get();
 let rows=snap.docs.map(d=>{let e=d.data();return `<tr><td><b>${e.nome||d.id}</b><br><small>${d.id}</small></td><td>${e.segmento||'—'}</td><td>${e.plano||'Starter'}</td><td>${e.status||'Ativa'}</td><td>${br(e.vencimento)||'—'}</td><td>${e.whats||'—'}</td><td><button class="btn sm" onclick="masterSetStatus('${d.id}','Ativa')">Ativar</button> <button class="btn redbtn sm" onclick="masterSetStatus('${d.id}','Bloqueada')">Bloquear</button></td></tr>`}).join('');
 $('p-master').innerHTML=`<div class="card"><div class="head"><h3>Painel Master — Empresas</h3><button class="btn" onclick="master()">Atualizar</button></div><table class="table"><thead><tr><th>Empresa</th><th>Segmento</th><th>Plano</th><th>Status</th><th>Vencimento</th><th>WhatsApp</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="7" class="empty">Nenhuma empresa.</td></tr>'}</tbody></table></div>`;
}
async function masterSetStatus(id,status){if(!isMaster)return; await db.collection('empresas').doc(id).set({status},{merge:true}); master();}
const oldRenderSaas=render;
render=function(p){ if(p=='loja')return loja(); if(p=='master')return master(); return oldRenderSaas(p); };
(async()=>{$('date').textContent=new Date().toLocaleDateString('pt-BR',{weekday:'long',day:'2-digit',month:'long',year:'numeric'});ensureSaasPages();nav();initSaasAuth();})();


/* =========================
   MAY BIKE V14 - ORGANIZAÇÃO PROFISSIONAL
   - Códigos automáticos por grupo
   - Migração automática dos cadastros antigos
   - Busca global
   - Histórico da bicicleta / garantia / capital parado / curva ABC
   ========================= */
function pad6(v){return String(Number(v||0)).padStart(6,'0')}
function hasCode(v){return v!==undefined&&v!==null&&String(v).trim()!==''}
function normalizeDigitsCode(v,start){let s=String(v||'').replace(/\D/g,'');return s?pad6(s):pad6(start||1)}
function ensureCountersV14(){st.counters={people:1,item:100001,bike:1,os:1,sale:1,account:1,purchase:1,...(st.counters||{})}}
function codeNum(c){let s=String(c||'').replace(/\D/g,'');return Number(s||0)}
function updateCounterFromCode(group,code){ensureCountersV14();let num=codeNum(code);if(num>=Number(st.counters[group]||0))st.counters[group]=num+1}
function nextCode(group,start,prefix=''){ensureCountersV14();let current=Number(st.counters[group]||start||1);let code=prefix+pad6(current);st.counters[group]=current+1;return code}
function assignCode(obj,group,start,prefix=''){if(!obj)return '';if(!hasCode(obj.cod)){obj.cod=nextCode(group,start,prefix)}else{obj.cod=prefix?String(obj.cod):normalizeDigitsCode(obj.cod,start);updateCounterFromCode(group,obj.cod)}return obj.cod}
function assignDocCode(obj,field,group,start,prefix){if(!obj)return '';if(!hasCode(obj[field])) obj[field]=nextCode(group,start,prefix); else updateCounterFromCode(group,obj[field]);return obj[field]}
function migrateV13(){
  st.config={multaPercent:2,jurosMesPercent:1,comissaoMecanicoPercent:5,comissaoVendedorPercent:3,margemPadrao:75,margemMinima:70,garantiaDias:90,revisaoDias:120,metaMensal:30000,...(st.config||{})};
  st.recorrentes=st.recorrentes||[];st.vendas=st.vendas||[];st.caixa=st.caixa||[];st.os=st.os||[];st.maoObra=st.maoObra||[];st.funcionarios=st.funcionarios||[];st.clientes=st.clientes||[];st.bikes=st.bikes||[];st.agenda=st.agenda||[];st.audit=st.audit||[];st.estoque=st.estoque||[];st.contas=st.contas||[];st.fornecedores=st.fornecedores||[];
  st.contas=st.contas.map(c=>({...c,valorOriginal:n(c.valorOriginal||c.valor),valor:n(c.valor),status:c.status||'Aberto'}));
  st.estoque=st.estoque.map(e=>({...e,precoCompra:n(e.precoCompra||e.custo),ipi:n(e.ipi),frete:n(e.frete),outrosCustos:n(e.outrosCustos),margem:n(e.margem||st.config.margemPadrao),custoReal:n(e.custoReal||e.custo)}));
  st.categoriasMargem=st.categoriasMargem||[{cat:'Câmaras',margem:70},{cat:'Pneus',margem:70},{cat:'Correntes',margem:75},{cat:'Acessórios',margem:100},{cat:'Bicicletas',margem:20}];
  ensureCountersV14();
  [...st.clientes,...st.funcionarios,...st.fornecedores].forEach(x=>assignCode(x,'people',1,''));
  [...st.estoque,...st.maoObra].forEach(x=>assignCode(x,'item',100001,''));
  st.bikes.forEach(b=>assignDocCode(b,'cod','bike',1,'B'));
  st.os.forEach(o=>{assignDocCode(o,'cod','os',1,'OS'); if(!o.garantiaAte&&o.status==='Faturada')o.garantiaAte=addDays(o.data||today(),st.config.garantiaDias||90)});
  st.vendas.forEach(v=>assignDocCode(v,'cod','sale',1,'VD'));
  st.contas.forEach(c=>assignDocCode(c,'cod','account',1,'CT'));
  st.pedidosCompra=st.pedidosCompra||[];st.pedidosCompra.forEach(p=>assignDocCode(p,'cod','purchase',1,'PC'));
}
