function clientes(){let rows=st.clientes.map(c=>{let bikes=(st.bikes||[]).filter(b=>b.clienteId==c.id).length, aberto=st.contas.filter(x=>x.cliente==c.nome&&x.tipo=='A Receber'&&x.status!='Pago').reduce((a,x)=>a+totalConta(x),0);return `<tr><td><b>${c.cod||'—'}</b></td><td><b>${c.nome}</b></td><td>${c.cpf||'—'}</td><td>${c.whats||'—'}</td><td>${c.cidade||'—'}</td><td>${bikes}</td><td class="${aberto>0?'red':'green'}">${money(aberto)}</td><td><button class="btn sm" onclick="copyCode('${c.cod||''}')">Copiar cód.</button> <button class="btn sm" onclick="openCliente('${c.id}')">Editar</button> <button class="btn sm" onclick="openBike('', '${c.id}')">+ Bike</button> <button class="btn redbtn sm" onclick="del('clientes','${c.id}')">Excluir</button></td></tr>`}).join('');$('p-clientes').innerHTML=`<div class="card"><div class="head"><h3>Clientes</h3><button class="btn goldbtn" onclick="openCliente()">+ Novo cliente</button></div><table class="table"><thead><tr><th>Código</th><th>Nome</th><th>CPF</th><th>WhatsApp</th><th>Cidade</th><th>Bikes</th><th>Em aberto</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="8" class="empty">Nenhum cliente.</td></tr>'}</tbody></table></div>`}
