function funcionarios(){let rows=st.funcionarios.map(f=>`<tr><td><b>${f.cod||'—'}</b></td><td><b>${f.nome}</b></td><td>${f.cargo||'—'}</td><td>${f.whats||'—'}</td><td>${f.email||'—'}</td><td>${f.ativo?'Ativo':'Inativo'}</td><td><button class="btn sm" onclick="copyCode('${f.cod||''}')">Copiar cód.</button> <button class="btn sm" onclick="openFunc('${f.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('funcionarios','${f.id}')">Excluir</button></td></tr>`).join('');$('p-funcionarios').innerHTML=`<div class="card"><div class="head"><h3>Funcionários</h3><button class="btn goldbtn" onclick="openFunc()">+ Novo funcionário</button></div><table class="table"><thead><tr><th>Código</th><th>Nome</th><th>Cargo/Função</th><th>WhatsApp</th><th>E-mail</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="7" class="empty">Nenhum funcionário cadastrado.</td></tr>'}</tbody></table></div>`}
