function maoObraPage(){let rows=(st.maoObra||[]).map(m=>`<tr><td><b>${m.cod||'—'}</b></td><td><b>${m.nome}</b></td><td>${m.cat||'—'}</td><td>${money(m.valor)}</td><td>${m.ativo?'Ativo':'Inativo'}</td><td><button class="btn sm" onclick="copyCode('${m.cod||''}')">Copiar cód.</button> <button class="btn sm" onclick="openMaoObra('${m.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('maoObra','${m.id}')">Excluir</button></td></tr>`).join('');$('p-maoobra').innerHTML=`<div class="card"><div class="head"><div><h3>Cadastro de Mão de Obra</h3><p style="color:var(--mut);margin:4px 0 0">Produtos e mão de obra usam a mesma sequência numérica iniciando em 100001.</p></div><button class="btn goldbtn" onclick="openMaoObra()">+ Nova mão de obra</button></div><table class="table"><thead><tr><th>Código</th><th>Serviço</th><th>Categoria</th><th>Valor padrão</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="6" class="empty">Nenhuma mão de obra cadastrada.</td></tr>'}</tbody></table></div>`}
