function estoque(){let totalCusto=st.estoque.reduce((a,e)=>a+n(e.qtd)*calcProduto(e).custoReal,0),totalVenda=st.estoque.reduce((a,e)=>{let c=calcProduto(e);return a+n(e.qtd)*n(e.venda||c.vendaSugerida)},0),lucroPot=st.estoque.reduce((a,e)=>a+n(e.qtd)*calcProduto(e).lucro,0),crit=st.estoque.filter(e=>n(e.qtd)<=n(e.min)).length,parado=produtosParados(180).length;let rows=st.estoque.map(e=>{let c=calcProduto(e),precoVenda=n(e.venda||c.vendaSugerida),valorVendaTotal=n(e.qtd)*precoVenda;return `<tr><td><b>${e.cod||'—'}</b></td><td><b>${e.desc}</b><br><small>${e.forn||''}</small></td><td>${e.cat||'—'}</td><td>${e.qtd}</td><td>${e.min}</td><td>${money(e.precoCompra||e.custo)}</td><td>${n(e.ipi)}%</td><td>${money(c.custoReal)}</td><td>${money(precoVenda)}</td><td>${money(valorVendaTotal)}</td><td class="${c.marginReal<n(st.config.margemMinima)?'red':'green'}">${c.marginReal.toFixed(1)}%</td><td>${money(c.lucro)}</td><td><button class="btn sm" onclick="copyCode('${e.cod||''}')">Copiar cód.</button> <button class="btn sm" onclick="openEst('${e.id}')">Editar</button> <button class="btn redbtn sm" onclick="del('estoque','${e.id}')">Excluir</button></td></tr>`}).join('');$('p-estoque').innerHTML=`<div class="grid4"><div class="metric"><div class="label">Capital em estoque</div><div class="value gold">${money(totalCusto)}</div></div><div class="metric"><div class="label">Valor de venda em estoque</div><div class="value green">${money(totalVenda)}</div></div><div class="metric"><div class="label">Lucro potencial</div><div class="value green">${money(lucroPot)}</div></div><div class="metric"><div class="label">Estoque crítico</div><div class="value red">${crit}</div></div><div class="metric"><div class="label">Parados 180+ dias</div><div class="value red">${parado}</div></div></div><div class="card"><div class="head"><div><h3>Estoque inteligente</h3><p style="color:var(--mut);margin:4px 0 0">Códigos automáticos, IPI, custo real, margem, preço sugerido e valor total de venda em estoque.</p></div><button class="btn goldbtn" onclick="openEst()">+ Produto/peça</button></div><table class="table"><thead><tr><th>Código</th><th>Descrição</th><th>Categoria</th><th>Qtd</th><th>Mín.</th><th>Compra</th><th>IPI</th><th>Custo real</th><th>Venda un.</th><th>Venda total</th><th>Margem</th><th>Lucro un.</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="13" class="empty">Nenhum item.</td></tr>'}</tbody></table></div>`}
function saveEst(id){let old=st.estoque.find(x=>x.id==id)||{};let base={precoCompra:n($('e_compra').value),ipi:n($('e_ipi').value),frete:n($('e_frete').value),outrosCustos:n($('e_outros').value),margem:n($('e_margem').value),cat:$('e_cat').value,venda:n($('e_venda').value)};let c=calcProduto(base);let obj={...old,id:id||uid(),cod:old.cod||v14ItemCode(),desc:$('e_desc').value,cat:$('e_cat').value,qtd:n($('e_qtd').value),min:n($('e_min').value),forn:$('e_forn').value,precoCompra:base.precoCompra,ipi:base.ipi,frete:base.frete,outrosCustos:base.outrosCustos,margem:base.margem,custo:c.custoReal,custoReal:c.custoReal,venda:base.venda||c.vendaSugerida,updatedAt:new Date().toISOString()};if(!obj.desc)return alert('Informe a descrição.');upsert('estoque',obj);logAudit(id?'Produto editado':'Produto cadastrado',`${obj.cod} - ${obj.desc}`);closeM();save()}
