function saveOS(id){let old=st.os.find(x=>x.id==id),func=st.funcionarios.find(f=>f.id==$('o_func').value),bikeId=$('o_bike_sel').value;let obj={...(old||{}),id:id||uid(),cod:old?old.cod:v14OSCode(),num:old?old.num:st.seqOS++,data:$('o_data').value,cliente:$('o_cli').value,bike:$('o_bike').value,bikeId,defeito:$('o_def').value,funcionarioId:$('o_func').value,funcionario:func?func.nome:'',status:$('o_status').value,desc:n($('o_desc').value),pecas:collectPecas(),mao:collectMao(),obs:$('o_obs').value,entregaPrevista:$('o_entrega').value,assinatura:$('o_ass').value,fotosAntes:JSON.parse($('fotosAntesBox').dataset.photos||'[]'),fotosDepois:JSON.parse($('fotosDepoisBox').dataset.photos||'[]'),baixouEstoque:old?!!old.baixouEstoque:false,garantiaAte:old?old.garantiaAte:''};if(!obj.cliente||!obj.bike)return alert('Informe cliente e bike.');if(obj.status=='Pronta para retirada'&&!obj.baixouEstoque){for(let p of obj.pecas){let e=st.estoque.find(x=>x.id==p.prodId);if(e){if(n(e.qtd)<n(p.qtd))return alert('Estoque insuficiente para: '+e.desc);e.qtd-=n(p.qtd)}}obj.baixouEstoque=true}if(obj.status=='Faturada'&&!obj.garantiaAte)obj.garantiaAte=addDays(obj.data||today(),st.config.garantiaDias||90);upsert('os',obj);logAudit(id?'OS editada':'OS criada',`${obj.cod} - ${obj.cliente}`);closeM();save()}
function receberOS(id){let o=st.os.find(x=>x.id==id),t=calcOS(o).total;let forma=$('pay_forma').value,entrada=n($('pay_entrada')?.value),parcelas=Math.max(1,n($('pay_parcelas')?.value||1)),venc=$('pay_venc')?.value||today();let v={id:uid(),cod:v14SaleCode(),num:st.seqVenda++,data:today(),cliente:o.cliente,origem:o.cod||('OS #'+o.num),osId:o.id,funcionario:o.funcionario,funcionarioId:o.funcionarioId,forma,total:t,status:forma=='A prazo'||forma=='Parcelado'||forma=='Parcial'?'A receber':'Recebida',itens:(o.pecas||[]).map(p=>({prodId:p.prodId,nome:p.nome,qtd:p.qtd,preco:p.preco}))};st.vendas.push(v);if(forma=='A prazo'||forma=='Parcelado'||forma=='Parcial'){let saldo=Math.max(0,t-entrada);if(entrada>0)st.caixa.push({id:uid(),data:today(),tipo:'Entrada',desc:'Entrada '+v.cod+' - '+o.cliente,cat:'Venda/OS',valor:entrada});let valorParc=saldo/parcelas;for(let i=0;i<parcelas;i++){let d=addDays(venc,30*i);st.contas.push({id:uid(),cod:v14ContaCode(),tipo:'A Receber',cliente:o.cliente,desc:`${v.cod} - ${o.cliente} - Parcela ${i+1}/${parcelas}`,venc:d,valor:valorParc,valorOriginal:valorParc,status:'Aberto',vendaId:v.id,osId:o.id})}}else{st.caixa.push({id:uid(),data:today(),tipo:'Entrada',desc:v.cod+' - '+o.cliente,cat:'Venda/OS',valor:t})}o.status='Faturada';if(!o.garantiaAte)o.garantiaAte=addDays(o.data||today(),st.config.garantiaDias||90);logAudit('OS faturada',`${o.cod||o.num} / venda ${v.cod}`);closeM();save()}
function vendas(){let prontas=st.os.filter(o=>o.status=='Pronta para retirada').map(o=>`<tr><td>${o.cod||('OS'+pad6(o.num||0))}</td><td>${o.cliente}</td><td>${o.funcionario||'—'}</td><td>${money(calcOS(o).total)}</td><td><button class="btn goldbtn sm" onclick="openPay('${o.id}')">Receber / Faturar</button></td></tr>`).join('');let vend=st.vendas.slice().reverse().map(v=>`<tr><td><b>${v.cod||'#'+v.num}</b></td><td>${br(v.data)}</td><td>${v.cliente}</td><td>${v.origem||'Venda rápida'}</td><td>${v.forma}</td><td>${money(v.total)}</td><td>${v.status||'Recebida'}</td><td><button class="btn sm" onclick="printRec('${v.id}')">Recibo</button></td></tr>`).join('');$('p-vendas').innerHTML=`<div class="grid2"><div class="card"><div class="head"><h3>OS prontas aguardando pagamento</h3></div><table class="table"><thead><tr><th>OS</th><th>Cliente</th><th>Funcionário</th><th>Total</th><th></th></tr></thead><tbody>${prontas||'<tr><td colspan="5" class="empty">Nenhuma OS pronta para faturar.</td></tr>'}</tbody></table></div><div class="card"><div class="head"><h3>Venda rápida</h3><button class="btn goldbtn" onclick="openVendaRapida()">+ Nova venda</button></div><div class="notice">V15 mantém venda à vista, parcial, parcelada e a prazo, gerando contas a receber automaticamente.</div></div></div><div class="card"><h3>Histórico de vendas</h3><table class="table"><thead><tr><th>Código</th><th>Data</th><th>Cliente</th><th>Origem</th><th>Pagamento</th><th>Total</th><th>Status</th><th></th></tr></thead><tbody>${vend||'<tr><td colspan="8" class="empty">Nenhuma venda.</td></tr>'}</tbody></table></div>`}
function contas(){gerarRecorrentes();let rec=contasAbertas('A Receber').reduce((a,c)=>a+totalConta(c),0),pag=contasAbertas('A Pagar').reduce((a,c)=>a+totalConta(c),0);let rows=st.contas.slice().sort((a,b)=>(a.venc||'').localeCompare(b.venc||'')).map(c=>`<tr><td><b>${c.cod||'—'}</b></td><td>${br(c.venc)}</td><td>${c.tipo}</td><td>${c.cliente||'—'}</td><td>${c.desc}</td><td>${money(totalConta(c))}</td><td>${statusConta(c)}</td><td><button class="btn sm" onclick="payConta('${c.id}')">Marcar pago</button> <button class="btn redbtn sm" onclick="del('contas','${c.id}')">Excluir</button></td></tr>`).join('');$('p-contas').innerHTML=`<div class="grid3"><div class="metric"><div class="label">A receber</div><div class="value green">${money(rec)}</div></div><div class="metric"><div class="label">A pagar</div><div class="value red">${money(pag)}</div></div><div class="metric"><div class="label">Fluxo projetado</div><div class="value ${rec-pag>=0?'green':'red'}">${money(rec-pag)}</div></div></div><div class="card"><div class="head"><h3>Contas a pagar/receber</h3><button class="btn goldbtn" onclick="openConta()">+ Nova conta</button></div><table class="table"><thead><tr><th>Código</th><th>Vencimento</th><th>Tipo</th><th>Cliente</th><th>Descrição</th><th>Valor c/ juros</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="8" class="empty">Nenhuma conta.</td></tr>'}</tbody></table></div><div class="card"><div class="head"><h3>Contas mensais recorrentes</h3><button class="btn" onclick="openRecorrente()">+ Recorrente</button></div>${recorrentesHTML()}</div>`}
function openConta(){modal(`<div class="mhead"><h3>Nova conta</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="form2"><div class="field"><label>Tipo</label><select id="ct_tipo"><option>A Pagar</option><option>A Receber</option></select></div><div class="field"><label>Vencimento</label><input id="ct_venc" type="date" value="${today()}"></div><div class="field"><label>Valor</label><input id="ct_valor" type="number" step="0.01"></div><div class="field"><label>Cliente/Fornecedor</label><input id="ct_cliente"></div></div><div class="field"><label>Descrição</label><input id="ct_desc"></div><div class="actions"><button class="btn goldbtn" onclick="saveContaManual()">Salvar</button></div>`)}
function saveContaManual(){let obj={id:uid(),cod:v14ContaCode(),tipo:$('ct_tipo').value,venc:$('ct_venc').value,valor:n($('ct_valor').value),valorOriginal:n($('ct_valor').value),cliente:$('ct_cliente').value,desc:$('ct_desc').value,status:'Aberto'};if(!obj.valor||!obj.desc)return alert('Informe valor e descrição.');st.contas.push(obj);logAudit('Conta cadastrada',`${obj.cod} - ${obj.desc}`);closeM();save()}
function dashboard(){migrateV13();let hoje=today(),m=monthKey(today()),ano=today().slice(0,4);let vendasMes=st.vendas.filter(v=>monthKey(v.data)==m),vendasAno=st.vendas.filter(v=>(v.data||'').slice(0,4)==ano);let fatMes=vendasMes.reduce((a,v)=>a+n(v.total),0),fatAno=vendasAno.reduce((a,v)=>a+n(v.total),0),lucroMes=vendasMes.reduce((a,v)=>a+lucroVenda(v),0);let crit=st.estoque.filter(e=>n(e.qtd)<=n(e.min)).length, vencidas=st.contas.filter(c=>c.status!='Pago'&&daysLate(c.venc)>0).length, prontas=st.os.filter(o=>o.status=='Pronta para retirada').length;let meta=n(st.config.metaMensal||0),perc=meta?Math.min(100,(fatMes/meta*100)):0;let abc=curvaABC();let parados=produtosParados(180);let rank=servicoRanking().slice(0,5).map(([s,q],i)=>`<tr><td>${i+1}º</td><td>${s}</td><td><b>${q}</b></td></tr>`).join('');$('p-dashboard').innerHTML=`<div class="card"><div class="head"><h3>Busca global V15</h3><span class="pill">Código, cliente, produto, OS ou bike</span></div><div class="form2"><input id="busca_global" placeholder="Digite um código ou nome. Ex: 000001, 100001, OS000001" oninput="buscaGlobal()"><button class="btn goldbtn" onclick="buscaGlobal()">Buscar</button></div><div id="busca_result" style="margin-top:12px"></div></div><div class="grid4"><div class="metric"><div class="label">Faturamento do mês</div><div class="value green">${money(fatMes)}</div></div><div class="metric"><div class="label">Lucro estimado mês</div><div class="value ${lucroMes>=0?'green':'red'}">${money(lucroMes)}</div></div><div class="metric"><div class="label">Meta mensal</div><div class="value gold">${perc.toFixed(0)}%</div><small>${money(fatMes)} / ${money(meta)}</small></div><div class="metric"><div class="label">Faturamento anual</div><div class="value green">${money(fatAno)}</div></div></div><div class="grid4"><div class="metric"><div class="label">Estoque crítico</div><div class="value red">${crit}</div></div><div class="metric"><div class="label">Contas vencidas</div><div class="value red">${vencidas}</div></div><div class="metric"><div class="label">Bikes prontas</div><div class="value blue">${prontas}</div></div><div class="metric"><div class="label">Produtos parados 180+</div><div class="value red">${parados.length}</div></div></div><div class="grid2"><div class="card"><h3>Ranking de serviços</h3><table class="table"><thead><tr><th>#</th><th>Serviço</th><th>Qtd.</th></tr></thead><tbody>${rank||'<tr><td colspan="3" class="empty">Sem serviços.</td></tr>'}</tbody></table></div><div class="card"><h3>Curva ABC de produtos</h3><table class="table"><thead><tr><th>Classe</th><th>Produtos</th><th>Faturamento</th></tr></thead><tbody><tr><td><b>A</b></td><td>${abc.A.qtd}</td><td>${money(abc.A.valor)}</td></tr><tr><td><b>B</b></td><td>${abc.B.qtd}</td><td>${money(abc.B.valor)}</td></tr><tr><td><b>C</b></td><td>${abc.C.qtd}</td><td>${money(abc.C.valor)}</td></tr></tbody></table></div></div>`}
function buscaGlobal(){let q=($('busca_global')?.value||'').toLowerCase().trim();if(!q){$('busca_result').innerHTML='';return}let res=[];function add(tipo,cod,titulo,desc,goTo){if((String(cod||'')+' '+String(titulo||'')+' '+String(desc||'')).toLowerCase().includes(q))res.push({tipo,cod,titulo,desc,goTo})}st.clientes.forEach(c=>add('Cliente',c.cod,c.nome,c.whats||c.cpf,'clientes'));st.funcionarios.forEach(f=>add('Funcionário',f.cod,f.nome,f.cargo,'funcionarios'));st.estoque.forEach(e=>add('Produto',e.cod,e.desc,`${e.cat||''} Estoque ${e.qtd}`,'estoque'));st.maoObra.forEach(m=>add('Mão de obra',m.cod,m.nome,m.cat,'maoobra'));st.bikes.forEach(b=>add('Bicicleta',b.cod,`${b.marca||''} ${b.modelo||''}`,b.quadro,'bicicletas'));st.os.forEach(o=>add('OS',o.cod||('OS'+pad6(o.num||0)),o.cliente,`${o.bike||''} ${o.status||''}`,'os'));st.vendas.forEach(v=>add('Venda',v.cod,v.cliente,money(v.total),'vendas'));st.contas.forEach(c=>add('Conta',c.cod,c.desc,`${c.tipo} ${money(totalConta(c))}`,'contas'));$('busca_result').innerHTML=res.length?`<table class="table"><thead><tr><th>Tipo</th><th>Código</th><th>Registro</th><th>Detalhe</th><th></th></tr></thead><tbody>${res.slice(0,30).map(r=>`<tr><td>${r.tipo}</td><td><b>${r.cod||'—'}</b></td><td>${r.titulo}</td><td>${r.desc||''}</td><td><button class="btn sm" onclick="go('${r.goTo}')">Abrir aba</button></td></tr>`).join('')}</tbody></table>`:'<div class="empty">Nenhum resultado encontrado.</div>'}
function copyCode(c){if(!c)return;navigator.clipboard?.writeText(c);alert('Código copiado: '+c)}
function garantiaBadge(o){if(!o.garantiaAte)return '—';let d=(new Date(o.garantiaAte+'T00:00:00')-new Date(today()+'T00:00:00'))/86400000;return d>=0?`<span class="badge b3">Em garantia até ${br(o.garantiaAte)}</span>`:`<span class="badge b5">Vencida em ${br(o.garantiaAte)}</span>`}
function historicoBike(bid){return st.os.filter(o=>o.bikeId==bid).sort((a,b)=>(b.data||'').localeCompare(a.data||''))}
function openHistoricoBike(bid){let b=st.bikes.find(x=>x.id==bid)||{}, hist=historicoBike(bid);modal(`<div class="mhead"><h3>Histórico da bike ${b.cod||''}</h3><button class="btn" onclick="closeM()">Fechar</button></div><div class="notice"><b>${b.marca||''} ${b.modelo||''}</b><br>Quadro: ${b.quadro||'—'}</div><table class="table"><thead><tr><th>OS</th><th>Data</th><th>Serviço</th><th>Total</th><th>Garantia</th></tr></thead><tbody>${hist.map(o=>`<tr><td>${o.cod||o.num}</td><td>${br(o.data)}</td><td>${(o.mao||[]).map(m=>m.desc).join(', ')||o.defeito}</td><td>${money(calcOS(o).total)}</td><td>${garantiaBadge(o)}</td></tr>`).join('')||'<tr><td colspan="5" class="empty">Sem histórico.</td></tr>'}</tbody></table>`)}
function produtosParados(dias){let limite=new Date();limite.setDate(limite.getDate()-dias);return st.estoque.filter(e=>{let mov=ultimoMovProduto(e.id);return !mov||new Date(mov+'T00:00:00')<limite})}
function ultimoMovProduto(prodId){let datas=[];st.vendas.forEach(v=>(v.itens||[]).forEach(i=>{if(i.prodId==prodId&&v.data)datas.push(v.data)}));st.os.forEach(o=>(o.pecas||[]).forEach(i=>{if(i.prodId==prodId&&o.data)datas.push(o.data)}));return datas.sort().pop()}
function curvaABC(){let arr=st.estoque.map(e=>{let valor=0;st.vendas.forEach(v=>(v.itens||[]).forEach(i=>{if(i.prodId==e.id)valor+=n(i.qtd)*n(i.preco)}));return {id:e.id,valor}}).sort((a,b)=>b.valor-a.valor);let total=arr.reduce((a,b)=>a+b.valor,0)||1,acc=0,out={A:{qtd:0,valor:0},B:{qtd:0,valor:0},C:{qtd:0,valor:0}};arr.forEach(x=>{acc+=x.valor;let pct=acc/total;let k=pct<=.8?'A':pct<=.95?'B':'C';out[k].qtd++;out[k].valor+=x.valor});return out}
function relatorios(){let ent=st.caixa.filter(x=>x.tipo=='Entrada').reduce((a,b)=>a+n(b.valor),0),sai=st.caixa.filter(x=>x.tipo=='Saída').reduce((a,b)=>a+n(b.valor),0),cost=st.estoque.reduce((a,e)=>a+n(e.qtd)*calcProduto(e).custoReal,0);let rec=contasAbertas('A Receber').reduce((a,c)=>a+totalConta(c),0),pag=contasAbertas('A Pagar').reduce((a,c)=>a+totalConta(c),0),res=rec-pag;let funcs=st.funcionarios.map(f=>{let q=st.os.filter(o=>o.funcionarioId==f.id).length, fat=st.vendas.filter(v=>v.funcionarioId==f.id||v.funcionario==f.nome).reduce((a,v)=>a+n(v.total),0), com=comissaoFunc(f);return `<tr><td>${f.cod||'—'}</td><td>${f.nome}</td><td>${f.cargo||'—'}</td><td>${q}</td><td>${money(fat)}</td><td>${money(com)}</td></tr>`}).join('');let abc=curvaABC(), parados=produtosParados(180);let rank=servicoRanking().map(([s,q],i)=>`<tr><td>${i+1}º</td><td>${s}</td><td>${q}</td></tr>`).join('');let months={};st.vendas.forEach(v=>{let k=monthKey(v.data);months[k]=months[k]||{fat:0,lucro:0};months[k].fat+=n(v.total);months[k].lucro+=lucroVenda(v)});let mesRows=Object.entries(months).sort().reverse().map(([k,v])=>`<tr><td>${k}</td><td>${money(v.fat)}</td><td>${money(v.lucro)}</td></tr>`).join('');$('p-relatorios').innerHTML=`<div class="grid3"><div class="metric"><div class="label">A receber aberto</div><div class="value green">${money(rec)}</div></div><div class="metric"><div class="label">A pagar aberto</div><div class="value red">${money(pag)}</div></div><div class="metric"><div class="label">Resultado por contas</div><div class="value ${res>=0?'green':'red'}">${res>=0?'Lucro ':'Prejuízo '}${money(Math.abs(res))}</div></div></div><div class="grid3"><div class="metric"><div class="label">Entradas no caixa</div><div class="value green">${money(ent)}</div></div><div class="metric"><div class="label">Saídas no caixa</div><div class="value red">${money(sai)}</div></div><div class="metric"><div class="label">Capital parado em estoque</div><div class="value gold">${money(cost)}</div></div></div><div class="toolbar" style="margin-bottom:14px"><button class="btn" onclick="exportRelatoriosCSV()">Exportar relatório CSV</button></div><div class="grid2"><div class="card"><h3>Relatório de comissão</h3><table class="table"><thead><tr><th>Código</th><th>Funcionário</th><th>Cargo</th><th>OS</th><th>Faturamento</th><th>Comissão</th></tr></thead><tbody>${funcs||'<tr><td colspan="6" class="empty">Sem funcionários.</td></tr>'}</tbody></table></div><div class="card"><h3>Ranking de serviços mais executados</h3><table class="table"><thead><tr><th>#</th><th>Serviço</th><th>Qtd.</th></tr></thead><tbody>${rank||'<tr><td colspan="3" class="empty">Sem serviços.</td></tr>'}</tbody></table></div></div><div class="grid2"><div class="card"><h3>Curva ABC</h3><table class="table"><thead><tr><th>Classe</th><th>Produtos</th><th>Faturamento</th></tr></thead><tbody><tr><td>A</td><td>${abc.A.qtd}</td><td>${money(abc.A.valor)}</td></tr><tr><td>B</td><td>${abc.B.qtd}</td><td>${money(abc.B.valor)}</td></tr><tr><td>C</td><td>${abc.C.qtd}</td><td>${money(abc.C.valor)}</td></tr></tbody></table></div><div class="card"><h3>Produtos parados 180+ dias</h3><table class="table"><thead><tr><th>Código</th><th>Produto</th><th>Qtd</th><th>Capital</th></tr></thead><tbody>${parados.slice(0,20).map(e=>`<tr><td>${e.cod}</td><td>${e.desc}</td><td>${e.qtd}</td><td>${money(n(e.qtd)*calcProduto(e).custoReal)}</td></tr>`).join('')||'<tr><td colspan="4" class="empty">Sem produtos parados.</td></tr>'}</tbody></table></div></div><div class="grid2"><div class="card"><h3>Faturamento mês a mês</h3><table class="table"><thead><tr><th>Mês</th><th>Faturamento</th><th>Lucro estimado</th></tr></thead><tbody>${mesRows||'<tr><td colspan="3" class="empty">Sem vendas.</td></tr>'}</tbody></table></div><div class="card"><h3>Resumo geral V15</h3><p>Clientes: <b>${st.clientes.length}</b></p><p>Funcionários: <b>${st.funcionarios.length}</b></p><p>Mão de obra: <b>${(st.maoObra||[]).length}</b></p><p>OS: <b>${st.os.length}</b></p><p>Vendas: <b>${st.vendas.length}</b></p><p>Custo em estoque: <b>${money(cost)}</b></p></div></div>`}

/* ===== PATCH V15.2 — CORREÇÃO ABA CONTAS A PAGAR/RECEBER ===== */
function contas(){
  try{ gerarRecorrentes(); }catch(e){ console.warn('recorrentes:', e); }
  st.contas = st.contas || [];
  st.config = st.config || {multaPercent:2, jurosMesPercent:1};
  const abertas = st.contas.filter(c=>c.status!=='Pago');
  const rec = abertas.filter(c=>c.tipo==='A Receber').reduce((a,c)=>a+totalConta(c),0);
  const pag = abertas.filter(c=>c.tipo==='A Pagar').reduce((a,c)=>a+totalConta(c),0);
  const vencidas = abertas.filter(c=>daysLate(c.venc)>0).length;
  const hojeMs = new Date(today()+'T00:00:00').getTime();
  const aVencer = abertas.filter(c=>{
    if(!c.venc) return false;
    const diff = (new Date(c.venc+'T00:00:00').getTime()-hojeMs)/86400000;
    return diff>=0 && diff<=5;
  }).length;
  const filtro = `<div class="toolbar" style="margin-bottom:14px">
    <button class="btn goldbtn" onclick="openConta()">+ Nova conta</button>
    <button class="btn" onclick="openRecorrente()">+ Conta mensal</button>
    <button class="btn" onclick="exportContasCSV()">Exportar CSV</button>
  </div>`;
  const rows = st.contas.slice().sort((a,b)=>(a.venc||'9999').localeCompare(b.venc||'9999')).map(c=>{
    const cls = c.status==='Pago'?'':(c.tipo==='A Receber'?'green':'red');
    const valor = totalConta(c);
    return `<tr>
      <td><b>${c.cod||'—'}</b></td>
      <td>${br(c.venc)}</td>
      <td><span class="badge ${c.tipo==='A Receber'?'b3':'b5'}">${c.tipo}</span></td>
      <td>${c.cliente||c.fornecedor||'—'}</td>
      <td>${c.desc||'—'}</td>
      <td class="${cls}"><b>${money(valor)}</b></td>
      <td>${statusConta(c)}</td>
      <td>${c.status==='Pago'?`<small>Pago em ${br(c.dataPago)||'—'}</small>`:`<button class="btn sm goldbtn" onclick="payConta('${c.id}')">Marcar pago/recebido</button>`} <button class="btn redbtn sm" onclick="del('contas','${c.id}')">Excluir</button></td>
    </tr>`;
  }).join('');
  $('p-contas').innerHTML = `
    <div class="grid4">
      <div class="metric"><div class="label">A receber em aberto</div><div class="value green">${money(rec)}</div></div>
      <div class="metric"><div class="label">A pagar em aberto</div><div class="value red">${money(pag)}</div></div>
      <div class="metric"><div class="label">Fluxo projetado</div><div class="value ${rec-pag>=0?'green':'red'}">${money(rec-pag)}</div></div>
      <div class="metric"><div class="label">Vencidas / a vencer</div><div class="value gold">${vencidas} / ${aVencer}</div></div>
    </div>
    <div class="notice">V15.2: aba Contas corrigida. Contas a prazo vindas das vendas aparecem aqui automaticamente, com juros/multa calculados quando passam do vencimento.</div>
    ${filtro}
    <div class="card"><div class="head"><h3>Contas a pagar e a receber</h3><span class="pill">${st.contas.length} registro(s)</span></div>
      <table class="table"><thead><tr><th>Código</th><th>Vencimento</th><th>Tipo</th><th>Cliente/Fornecedor</th><th>Descrição</th><th>Valor c/ juros</th><th>Status</th><th></th></tr></thead><tbody>${rows||'<tr><td colspan="8" class="empty">Nenhuma conta cadastrada.</td></tr>'}</tbody></table>
    </div>
    <div class="card"><div class="head"><h3>Contas mensais recorrentes</h3><button class="btn" onclick="openRecorrente()">+ Recorrente</button></div>${recorrentesHTML()}</div>`;
}
function recorrentesHTML(){
  st.recorrentes = st.recorrentes || [];
  if(!st.recorrentes.length) return '<div class="empty">Nenhuma conta mensal recorrente cadastrada.</div>';
  return `<table class="table"><thead><tr><th>Tipo</th><th>Dia</th><th>Descrição</th><th>Valor</th><th>Status</th><th></th></tr></thead><tbody>${st.recorrentes.map(r=>`<tr><td>${r.tipo}</td><td>Dia ${r.dia||5}</td><td>${r.desc||'—'}</td><td>${money(r.valor)}</td><td>${r.ativo?'Ativa':'Inativa'}</td><td><button class="btn sm" onclick="toggleRecorrente('${r.id}')">${r.ativo?'Desativar':'Ativar'}</button> <button class="btn redbtn sm" onclick="delRecorrente('${r.id}')">Excluir</button></td></tr>`).join('')}</tbody></table>`;
}
function payConta(id){
  const c = st.contas.find(x=>x.id===id); if(!c) return alert('Conta não encontrada.');
  const valor = totalConta(c);
  modal(`<div class="mhead"><h3>${c.tipo==='A Receber'?'Receber conta':'Pagar conta'} ${c.cod||''}</h3><button class="btn" onclick="closeM()">Fechar</button></div>
    <div class="notice"><b>${c.desc||'Conta'}</b><br>Vencimento: ${br(c.venc)}<br>Valor atualizado: <b>${money(valor)}</b></div>
    <div class="form2"><div class="field"><label>Data</label><input id="pc_data" type="date" value="${today()}"></div><div class="field"><label>Forma</label><select id="pc_forma"><option>Dinheiro</option><option>PIX</option><option>Débito</option><option>Crédito</option><option>Transferência</option></select></div></div>
    <div class="field"><label>Observação</label><input id="pc_obs" placeholder="Opcional"></div>
    <div class="actions"><button class="btn goldbtn" onclick="confirmPayConta('${id}')">Confirmar</button></div>`);
}
function confirmPayConta(id){
  const c = st.contas.find(x=>x.id===id); if(!c) return;
  const valor = totalConta(c); const forma = $('pc_forma').value; const data = $('pc_data').value || today();
  c.status='Pago'; c.dataPago=data; c.formaPago=forma; c.valorPago=valor; c.obsPago=$('pc_obs').value;
  st.caixa = st.caixa || [];
  st.caixa.push({id:uid(),data,tipo:c.tipo==='A Receber'?'Entrada':'Saída',desc:`${c.cod||''} - ${c.desc||''}`,cat:c.tipo,valor,forma});
  logAudit('Conta baixada',`${c.cod||''} - ${c.desc||''}`);
  closeM(); save();
}
function toggleRecorrente(id){let r=(st.recorrentes||[]).find(x=>x.id===id); if(!r)return; r.ativo=!r.ativo; save()}
function delRecorrente(id){if(!confirm('Excluir recorrência? As contas já geradas permanecem.'))return; st.recorrentes=(st.recorrentes||[]).filter(x=>x.id!==id); save()}
function exportContasCSV(){
  const rows=[['codigo','vencimento','tipo','cliente_fornecedor','descricao','valor_atualizado','status','data_pago','forma_pago']];
  (st.contas||[]).forEach(c=>rows.push([c.cod||'',c.venc||'',c.tipo||'',c.cliente||c.fornecedor||'',c.desc||'',String(totalConta(c)).replace('.',','),c.status||'',c.dataPago||'',c.formaPago||'']));
  const csv=rows.map(r=>r.map(v=>'"'+String(v).replace(/"/g,'""')+'"').join(';')).join('\n');
  const blob=new Blob([csv],{type:'text/csv;charset=utf-8'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='maybike_contas.csv'; a.click();
}

/* ===== PATCH V15.2 — LOGO OFICIAL + GARANTIAS SEPARADAS ===== */
try{
  st.config = st.config || {};
  if(st.config.garantiaPecasDias==null) st.config.garantiaPecasDias = 90;
  if(st.config.garantiaMaoObraDias==null) st.config.garantiaMaoObraDias = 30;
}catch(e){console.warn('config v15.2',e)}

function garantiaDate(base, dias){ return addDays(base || today(), Number(dias||0)); }
function warrantyClass(date){
  if(!date) return 'warranty-warn';
  const diff=(new Date(date+'T00:00:00')-new Date(today()+'T00:00:00'))/86400000;
  return diff<0?'warranty-expired':diff<=7?'warranty-warn':'warranty-ok';
}
function warrantyText(date){
  if(!date) return 'Não gerada';
  const diff=Math.ceil((new Date(date+'T00:00:00')-new Date(today()+'T00:00:00'))/86400000);
  if(diff<0) return `Vencida em ${br(date)}`;
  if(diff===0) return `Vence hoje (${br(date)})`;
  return `Ativa até ${br(date)} (${diff} dias)`;
}
function logoPrintHTML(){return `<div class="print-logo-wrap"><img class="logo-mini-print" src="icons/maybike-logo.png"><div><b>WhatsApp:</b> (42) 98842-5435 &nbsp; | &nbsp; <b>E-mail:</b> maybikee@gmail.com</div><div><b>Sua bike. Seu estilo.</b></div></div>`}

const _render_v152 = render;
render = function(p){ if(p==='garantias') return garantiasPage(); return _render_v152(p); };

const _receberOS_v152_base = receberOS;
receberOS = function(id){
  let o=st.os.find(x=>x.id==id); if(!o) return alert('OS não encontrada.');
  let beforeVendas=(st.vendas||[]).length;
  _receberOS_v152_base(id);
  // Se a venda foi criada, registra garantias separadas pela data da venda/faturamento.
  let v=(st.vendas||[])[st.vendas.length-1];
  if(v && (st.vendas.length>beforeVendas || v.osId===id)){
    const base=v.data||today();
    v.garantiaPecasAte = (o.pecas||[]).length ? garantiaDate(base, st.config.garantiaPecasDias||90) : '';
    v.garantiaMaoObraAte = (o.mao||[]).length ? garantiaDate(base, st.config.garantiaMaoObraDias||30) : '';
    v.garantiaTexto = `Peças: ${st.config.garantiaPecasDias||90} dias | Mão de obra: ${st.config.garantiaMaoObraDias||30} dias`;
    o.garantiaPecasAte = v.garantiaPecasAte;
    o.garantiaMaoObraAte = v.garantiaMaoObraAte;
    o.garantiaAte = v.garantiaPecasAte || v.garantiaMaoObraAte || o.garantiaAte;
    save();
  }
};

