(function(){
  const VERSION_LABEL='V15.5 Documento de Venda Enterprise';
  const oldMigrateV13 = (typeof migrateV13 === 'function') ? migrateV13 : function(){};
  window.migrateV13 = function(){
    oldMigrateV13();
    st.bikesVendidas = st.bikesVendidas || [];
    st.seqDocumento = st.seqDocumento || 1;
    st.config = { garantiaBicicletaDias: 90, revisaoPosVendaDias: 30, ...st.config };
    (st.vendas||[]).forEach(v=>{ if(!v.docCod){ v.docCod='DV'+String(v.num||st.seqDocumento++).padStart(6,'0'); }});
    try{ document.title='May Bike ERP - May Bike — V15.5 Documento de Venda'; }catch(e){}
  };
  const oldSave = save;
  window.save = async function(){ migrateV13(); return oldSave(); };

  function clienteFromNome(nome){return (st.clientes||[]).find(c=>(c.nome||'')==(nome||''))||{};}
  function saleBikeInfoFromInputs(){
    return {
      tipo:$('vr_tipo_produto')?.value||'Produto/peça',
      marca:$('vr_marca')?.value||'',
      modelo:$('vr_modelo')?.value||'',
      cor:$('vr_cor')?.value||'',
      aro:$('vr_aro')?.value||'',
      tamanho:$('vr_tamanho')?.value||'',
      ano:$('vr_ano')?.value||'',
      quadro:$('vr_quadro')?.value||'',
      ncm:$('vr_ncm')?.value||'',
      cfop:$('vr_cfop')?.value||'',
      codBarras:$('vr_cod_barras')?.value||'',
      nfCompra:$('vr_nf_compra')?.value||'',
      nfVenda:$('vr_nf_venda')?.value||''
    };
  }
  function registerBikeSold(venda){
    if(!venda || !venda.bikeVenda || !venda.bikeVenda.quadro) return;
    let q=(venda.bikeVenda.quadro||'').trim().toUpperCase();
    if(!q) return;
    let exists=(st.bikesVendidas||[]).find(b=>(b.quadro||'').trim().toUpperCase()==q && b.vendaId==venda.id);
    if(exists) return;
    st.bikesVendidas.push({
      id:uid(), cod:'BV'+String((st.bikesVendidas||[]).length+1).padStart(6,'0'), vendaId:venda.id, vendaCod:venda.docCod||('DV'+String(venda.num||0).padStart(6,'0')),
      cliente:venda.cliente, data:venda.data||today(), valor:venda.total, garantiaAte:addDays(venda.data||today(), n(st.config.garantiaBicicletaDias||90)),
      revisaoAte:addDays(venda.data||today(), n(st.config.revisaoPosVendaDias||30)), ...venda.bikeVenda
    });
  }
  window.registrarBikesVendidasPendentes = function(){ (st.vendas||[]).forEach(registerBikeSold); };

  window.vendas = function(){
    migrateV13(); registrarBikesVendidasPendentes();
    let prontas=st.os.filter(o=>o.status=='Pronta para retirada').map(o=>`<tr><td>${o.cod||('OS'+String(o.num||0).padStart(6,'0'))}</td><td>${o.cliente}</td><td>${o.funcionario||'—'}</td><td>${money(calcOS(o).total)}</td><td><button class="btn goldbtn sm" onclick="openPay('${o.id}')">Receber / Faturar</button></td></tr>`).join('');
    let vend=st.vendas.slice().reverse().map(v=>`<tr><td><b>${v.docCod||v.cod||'#'+v.num}</b></td><td>${br(v.data)}</td><td>${v.cliente}</td><td>${v.origem||'Venda rápida'}</td><td>${v.bikeVenda?.quadro||'—'}</td><td>${v.forma}</td><td>${money(v.total)}</td><td>${v.status||'Recebida'}</td><td><button class="btn sm" onclick="printDocumentoVenda('${v.id}')">Doc. venda</button> <button class="btn sm" onclick="printRec('${v.id}')">Recibo</button></td></tr>`).join('');
    let bikes=(st.bikesVendidas||[]).slice().reverse().map(b=>`<tr><td><b>${b.cod}</b></td><td>${br(b.data)}</td><td>${b.cliente||'—'}</td><td>${[b.marca,b.modelo,b.cor,b.aro?('Aro '+b.aro):''].filter(Boolean).join(' ')||'—'}</td><td><b>${b.quadro||'—'}</b></td><td>${money(b.valor)}</td><td>${br(b.garantiaAte)}</td><td><button class="btn sm" onclick="printDocumentoVenda('${b.vendaId}')">Documento</button></td></tr>`).join('');
    $('p-vendas').innerHTML=`<div class="grid2"><div class="card"><div class="head"><h3>OS prontas aguardando pagamento</h3></div><table class="table"><thead><tr><th>OS</th><th>Cliente</th><th>Funcionário</th><th>Total</th><th></th></tr></thead><tbody>${prontas||'<tr><td colspan="5" class="empty">Nenhuma OS pronta para faturar.</td></tr>'}</tbody></table></div><div class="card"><div class="head"><h3>Venda rápida / Bicicleta</h3><button class="btn goldbtn" onclick="openVendaRapida()">+ Nova venda</button></div><div class="notice">V15.5 gera <b>Documento de Venda e Garantia</b> com cliente, descrição, número do quadro, campos fiscais internos e garantias. Não substitui NF-e/NFC-e oficial.</div></div></div><div class="card"><h3>Histórico de vendas</h3><table class="table"><thead><tr><th>Documento</th><th>Data</th><th>Cliente</th><th>Origem</th><th>Nº Quadro</th><th>Pagamento</th><th>Total</th><th>Status</th><th></th></tr></thead><tbody>${vend||'<tr><td colspan="9" class="empty">Nenhuma venda.</td></tr>'}</tbody></table></div><div class="card"><div class="head"><h3>🚲 Bicicletas vendidas</h3><button class="btn" onclick="exportBikesVendidasCSV()">Exportar CSV</button></div><table class="table"><thead><tr><th>Código</th><th>Data</th><th>Cliente</th><th>Bicicleta</th><th>Nº Quadro</th><th>Valor</th><th>Garantia até</th><th></th></tr></thead><tbody>${bikes||'<tr><td colspan="8" class="empty">Nenhuma bicicleta vendida registrada.</td></tr>'}</tbody></table></div>`;
  };

  window.openVendaRapida = function(){
    let cliOpts=(st.clientes||[]).map(c=>`<option value="${c.nome}">${c.nome}</option>`).join('');
    modal(`<div class="mhead"><h3>Venda rápida / Documento de venda</h3><button class="btn" onclick="closeM()">Fechar</button></div>
      <div class="form2"><div class="field"><label>Cliente</label><input id="vr_cli" list="clientesList" placeholder="Consumidor"><datalist id="clientesList">${cliOpts}</datalist></div><div class="field"><label>Tipo da venda</label><select id="vr_tipo_produto"><option>Produto/peça</option><option>Bicicleta</option><option>Acessório</option></select></div></div>
      <div class="card"><h3>Produtos</h3>${pecasHTML([])}</div>
      <div class="card"><h3>Dados para Documento de Venda / Bicicleta</h3><div class="form3"><div class="field"><label>Nº do quadro</label><input id="vr_quadro" placeholder="Obrigatório para bicicletas"></div><div class="field"><label>Marca</label><input id="vr_marca" placeholder="Ex: First, Caloi, Oggi"></div><div class="field"><label>Modelo</label><input id="vr_modelo"></div><div class="field"><label>Cor</label><input id="vr_cor"></div><div class="field"><label>Aro</label><input id="vr_aro" placeholder="29, 26, 20..."></div><div class="field"><label>Tamanho do quadro</label><input id="vr_tamanho"></div><div class="field"><label>Ano</label><input id="vr_ano"></div><div class="field"><label>Código de barras</label><input id="vr_cod_barras"></div><div class="field"><label>NF-e/NFC-e nº</label><input id="vr_nf_venda" placeholder="Preencher após emissão oficial"></div><div class="field"><label>NCM</label><input id="vr_ncm"></div><div class="field"><label>CFOP</label><input id="vr_cfop"></div><div class="field"><label>Nota de compra</label><input id="vr_nf_compra"></div></div><div class="notice">Esse documento é interno de venda/garantia e não substitui nota fiscal eletrônica oficial.</div></div>
      ${payHTML(0)}<div class="actions"><button class="btn goldbtn" onclick="saveVendaRapida()">Finalizar venda e gerar documento</button></div>`)
  };

  window.saveVendaRapida = function(){
    let itens=collectPecas(), total=itens.reduce((a,i)=>a+i.qtd*i.preco,0); if(!itens.length)return alert('Adicione produtos.');
    let bikeInfo=saleBikeInfoFromInputs(); if(bikeInfo.tipo=='Bicicleta' && !bikeInfo.quadro.trim()) return alert('Para venda de bicicleta, informe o número do quadro.');
    for(let p of itens){let e=st.estoque.find(x=>x.id==p.prodId); if(e){if(e.qtd<p.qtd)return alert('Estoque insuficiente para '+e.desc); e.qtd-=p.qtd}}
    let forma=$('pay_forma').value, entrada=total, status='Recebida'; if(['A prazo','Parcial','Crédito Parcelado'].includes(forma)){entrada=n($('pay_entrada').value); status=entrada>0?'Parcial / a receber':'A receber'}
    let v={id:uid(),num:st.seqVenda++,docCod:'DV'+String(st.seqDocumento++).padStart(6,'0'),data:today(),cliente:$('vr_cli').value||'Consumidor',origem:bikeInfo.tipo=='Bicicleta'?'Venda de bicicleta':'Venda rápida',total,forma,obs:$('pay_obs').value,status,entrada,itens,bikeVenda:bikeInfo,garantiaPecasAte:addDays(today(),90),garantiaMaoObraAte:addDays(today(),30)};
    st.vendas.push(v); registerBikeSold(v); if(entrada>0)addCaixa('Entrada',entrada,(v.docCod||'Venda')+' — '+v.cliente,'Venda Produto'); if(entrada<total)gerarContasReceber(v,total,entrada,$('pay_parcelas')?.value,$('pay_venc')?.value); closeM(); save(); setTimeout(()=>printDocumentoVenda(v.id),300);
  };

  window.printDocumentoVenda = function(id){
    let v=(st.vendas||[]).find(x=>x.id==id); if(!v) return alert('Venda não encontrada.');
    let c=clienteFromNome(v.cliente), b=v.bikeVenda||{};
    const itens=(v.itens||[]).map(i=>`<tr><td>${i.nome||i.desc||'Item'}</td><td>${i.qtd||1}</td><td>${money(i.preco||0)}</td><td>${money(n(i.qtd||1)*n(i.preco||0))}</td></tr>`).join('');
    $('print').innerHTML=`<div class="os-print-page" style="font-family:Arial,sans-serif;color:#111;font-size:12px;">
      ${logoPrintHTML()}
      <div style="text-align:center;border-bottom:2px solid #111;padding:8px 0;margin-bottom:10px;"><h2 style="margin:0;font-size:20px;">DOCUMENTO DE VENDA E GARANTIA ${v.docCod||('DV'+String(v.num||0).padStart(6,'0'))}</h2><small>Documento interno de venda. Não substitui NF-e/NFC-e oficial.</small></div>
      <p><b>Cliente:</b> ${v.cliente||'—'} &nbsp; <b>CPF:</b> ${c.cpf||'—'} &nbsp; <b>WhatsApp:</b> ${c.whats||'—'}</p>
      <p><b>Endereço:</b> ${c.end||'—'} ${c.cidade||''}</p>
      <p><b>Data da venda:</b> ${br(v.data)} &nbsp; <b>Forma de pagamento:</b> ${v.forma||'—'} &nbsp; <b>Status:</b> ${v.status||'—'}</p>
      <table style="width:100%;border-collapse:collapse;margin-top:10px" border="1" cellpadding="6"><thead><tr><th>Descrição</th><th>Qtd</th><th>Unitário</th><th>Total</th></tr></thead><tbody>${itens}<tr><td colspan="3"><b>TOTAL</b></td><td><b>${money(v.total)}</b></td></tr></tbody></table>
      <div style="margin-top:12px;border:1px solid #111;padding:10px"><h3 style="margin:0 0 8px">Dados da bicicleta / produto</h3><p><b>Tipo:</b> ${b.tipo||'Produto/peça'} &nbsp; <b>Marca:</b> ${b.marca||'—'} &nbsp; <b>Modelo:</b> ${b.modelo||'—'} &nbsp; <b>Cor:</b> ${b.cor||'—'} &nbsp; <b>Aro:</b> ${b.aro||'—'}</p><p><b>Nº do quadro:</b> ${b.quadro||'—'} &nbsp; <b>Tamanho:</b> ${b.tamanho||'—'} &nbsp; <b>Ano:</b> ${b.ano||'—'}</p><p><b>NCM:</b> ${b.ncm||'—'} &nbsp; <b>CFOP:</b> ${b.cfop||'—'} &nbsp; <b>Cód. barras:</b> ${b.codBarras||'—'} &nbsp; <b>NF-e/NFC-e nº:</b> ${b.nfVenda||'—'}</p></div>
      <div style="margin-top:12px;border:1px solid #111;padding:10px"><h3 style="margin:0 0 8px">Garantia</h3><p><b>Peças/produto:</b> 90 dias a partir da venda — válida até ${br(addDays(v.data||today(),90))}.</p><p><b>Mão de obra:</b> 30 dias quando houver serviço executado.</p><small>Garantia válida mediante apresentação deste documento e/ou OS. Não cobre mau uso, quedas, desgaste natural, alterações feitas por terceiros ou ausência de manutenção preventiva.</small></div>
      <div style="margin-top:12px;border:1px solid #111;padding:10px"><h3 style="margin:0 0 8px">Termo de ciência</h3><p>Declaro que recebi o produto/bicicleta acima conferido, ciente das condições de pagamento, garantia e orientações da May Bike.</p><p><b>Assinatura do cliente:</b> ____________________________________</p></div>
      <br><p>Assinatura May Bike: ________________________________</p>
    </div>`; setTimeout(()=>window.print(),100);
  };

  const oldPrintRec = printRec;
  window.printRec = function(id){ let v=(st.vendas||[]).find(x=>x.id==id); if(v) return printDocumentoVenda(id); return oldPrintRec(id); };

  const oldBuscaGlobal = (typeof buscaGlobal==='function') ? buscaGlobal : null;
  window.buscaGlobal = function(){
    let q=($('busca_global')?.value||'').toLowerCase().trim(); if(!q){ if($('busca_result'))$('busca_result').innerHTML=''; return; }
    let res=[];
    (st.bikesVendidas||[]).forEach(b=>{ if([b.cod,b.quadro,b.cliente,b.marca,b.modelo,b.vendaCod].some(x=>String(x||'').toLowerCase().includes(q))) res.push(`<div class="notice">🚲 <b>Bicicleta vendida:</b> ${b.marca||''} ${b.modelo||''} — Quadro <b>${b.quadro||'—'}</b> — Cliente ${b.cliente||'—'} — Venda ${b.vendaCod||'—'}</div>`); });
    if(oldBuscaGlobal){ oldBuscaGlobal(); let old=$('busca_result')?.innerHTML||''; if($('busca_result')) $('busca_result').innerHTML=old+res.join(''); }
    else if($('busca_result')) $('busca_result').innerHTML=res.join('')||'<div class="empty">Nada encontrado.</div>';
  };

  window.exportBikesVendidasCSV=function(){csvDownload('bicicletas_vendidas_maybike.csv', [['Código','Data','Cliente','Marca','Modelo','Cor','Aro','Nº Quadro','Valor','Garantia até','Venda'],...(st.bikesVendidas||[]).map(b=>[b.cod,br(b.data),b.cliente,b.marca,b.modelo,b.cor,b.aro,b.quadro,money(b.valor),br(b.garantiaAte),b.vendaCod])])};

  const oldDashboard = dashboard;
  window.dashboard = function(){ oldDashboard(); try{ let box=document.createElement('div'); box.className='metric'; let mes=monthKey(today()); let bikes=(st.bikesVendidas||[]).filter(b=>monthKey(b.data)==mes); let val=bikes.reduce((a,b)=>a+n(b.valor),0); box.innerHTML=`<div class="label">Bicicletas vendidas mês</div><div class="value green">${bikes.length}</div><small>${money(val)}</small>`; let grid=document.querySelector('#p-dashboard .grid4'); if(grid) grid.appendChild(box); }catch(e){} };

  migrateV13(); registrarBikesVendidasPendentes();
})();